To create a C program for Raspberry Pi 3 Model B+ that interfaces with a Silicon Labs Si1133 UV/ALS/IR sensor using the `wiringPiI2C` library, follows these steps:

1. Install the required libraries:

```bash
sudo apt-get update
sudo apt-get install wiringPi
```

2. Create a new C file, e.g., `si1133.c` and include the necessary headers:

```c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/mman.h>
#include <wiringPiI2C.h>
#include <time.h>

#define SI1133_ADDR 0x29  // I2C address of the Si1133 sensor

struct sensor_data {
    uint16_t uv_index;
    uint16_t als;
    uint16_t ir;
    time_t timestamp;
};

void handle_i2c_error(int error_code) {
    switch (error_code) {
        case WiringPiI2C_ERR_NO_DEVICE:
            printf("I2C error: No device found at the specified address\n");
            break;
        case WiringPiI2C_ERR_NO_ACK:
            printf("I2C error: No ACK received from the device\n");
            break;
        case WiringPiI2C_ERR_NO_DATA:
            printf("I2C error: No data received from the device\n");
            break;
        case WiringPiI2C_ERR_OVERFLOW:
            printf("I2C error: Data overflow\n");
            break;
        case WiringPiI2C_ERR_TIMEOUT:
            printf("I2C error: Timeout while communicating with the device\n");
            break;
        default:
            printf("I2C error: Unknown error code %d\n", error_code);
    }
}

int main() {
    int file_fd;
    int i2c_fd;
    struct sensor_data sensor_data;
    char log_filename[] = "light_data.log";

    // Initialize wiringPi and set up the I2C bus
    wiringPiSetup();
    i2c_fd = wiringPiI2CSetup(SI1133_ADDR);

    // Open the log file
    file_fd = open(log_filename, O_WRONLY | O_CREAT | O_APPEND, S_IRUSR | S_IWUSR | S_IRGRP | S_IROTH);
    if (file_fd < 0) {
        perror("Error opening log file");
        return 1;
    }

    while (1) {
        // Read data from the Si1133 sensor
        if (wiringPiI2CReadReg16(i2c_fd, 0x80, &sensor_data.uv_index) != WiringPiI2C_ERR_NONE ||
            wiringPiI2CReadReg16(i2c_fd, 0x82, &sensor_data.als) != WiringPiI2C_ERR_NONE ||
            wiringPiI2CReadReg16(i2c_fd, 0x84, &sensor_data.ir) != WiringPiI2C_ERR_NONE) {
            handle_i2c_error(wiringPiI2CReadReg16(i2c_fd, 0x00, NULL));
            continue;
        }

        // Get the current timestamp
        sensor_data.timestamp = time(NULL);

        // Write the sensor data to the log file
        if (write(file_fd, &sensor_data, sizeof(struct sensor_data)) != sizeof(struct sensor_data)) {
            perror("Error writing to log file");
        }

        // Print the sensor data to the console
        printf("UV index: %d\n", sensor_data.uv_index);
        printf("ALS: %d\n", sensor_data.als);
        printf("IR: %d\n", sensor_data.ir);
        printf("Timestamp: %s\n", ctime(&sensor_data.timestamp));

        sleep(1);
    }

    // Close the log file and the I2C bus
    close(file_fd);
    wiringPiI2CClose(i2c_fd);

    return 0;
}
```

3. Compile the C file:

```bash
gcc si1133.c -o si1133 -lwiringPi
```

4. Run the compiled program:

```bash
sudo ./si1133
```

