To create a C program for Raspberry Pi 3 Model B+ using the `pigpio` library to handle an HC-SR501 PIR sensor and a buzzer, follow the steps below:

1. Install the pigpio library on your Raspberry Pi:

```bash
sudo apt-get update
sudp apt-get install pigpio
```

2. Create a new C file, `pir_buzzer.c`, and paste the following code:

```c
#include <stdio.h>
#include <unistd.h>
#include <pigpio.h>

#define BUZZER_PIN 18
#define PIR_PIN 17
#define TIME_BETWEEN_BEEPS 500000

static volatile sig_atomic_t running = 1;

void pir_interrupt_handler(int gpio, int level, uint32_t tick) {
    (void)tick; // Unused parameter

    running = 1;
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    gpioWrite(BUZZER_PIN, 1);

    usleep(TIME_BETWEEN_BEEPS);
    gpioWrite(BUZZER_PIN, 0);
}

int main() {
    int pi_ret;
    int i;

    if ((pi_ret = pigpio_init()) < 0) {
        fprintf(stderr, "Failed to initialize pigpio library: %s\n", strerror(-pi_ret));
        return 1;
    }

    if (gpioInitialise() < 0) {
        fprintf(stderr, "Failed to initialize GPIO: %s\n", strerror(errno));
        return 1;
    }

    gpioSetMode(PIR_PIN, PI_INPUT);
    gpioSetAlertFunc(PIR_PIN, pigpio_callback(pir_interrupt_handler));

    while (running) {
        usleep(100000);
    }

    gpioTerm();
    pigpio_stop();

    return 0;
}
```

3. Compile the program:

```bash
gcc -o pir_buzzer pir_buzzer.c -lpigpio -lrt
```

4. Run the compiled program:

```bash
sudo ./pir_buzzer
```

