        perror("Failed to acquire I2C address");
        close(dev->file);
        return -1;
    }

    dev->map = mmap(NULL, 32, PROT_READ | PROT_WRITE, MAP_SHARED, dev->file, 0);
    if (dev->map == MAP_FAILED) {
        perror("Failed to map I2C device");
        close(dev->file);
        return -1;
    }

    return 0;
}

void i2c_read(struct i2c_data *dev, uint8_t reg, uint8_t *data, size_t size) {
    if (i2c_smbus_read_i2c_block_data(dev->file, reg, size, data) != size) {
        perror("Failed to read from I2C device");
    }
}

void i2c_write(struct i2c_data *dev, uint8_t reg, uint8_t value) {
    if (i2c_smbus_write_byte_data(dev->file, reg, value) < 0) {
        perror("Failed to write to I2C device");
    }
}

void gpio_pwm_setup(int gpio) {
    int fd_gpio = open("/dev/gpiochip0", O_RDWR);
    struct gpiochip *gpiochip = mmap(NULL, sizeof(struct gpiochip), PROT_READ | PROT_WRITE, MAP_SHARED, fd_gpio, 0);

    gpiochip->base = gpio;
    gpiochip->ngpio = 1;
    gpiochip->can_sleep = 1;
    gpiochip->label = "Fan PWM";

    if (ioctl(fd_gpio, GPIOCHIP, gpiochip) < 0) {
        perror("Failed to register GPIO chip");
    }

    gpio_tlm_config(fd_gpio, gpio, GPIO_TLM_OUTPUT2, 0);
    gpio_tlm_config(fd_gpio, gpio, GPIO_PULLUP_DOWN_OFF, 0);

    gpio_set_function(gpio, GPIO_FUNC_PWM);
    gpio_pwm_set_mode(gpio, GPIO_PWM_MODE_MS_MS);
    gpio_pwm_set_range(gpio, 0, 100);
    gpio_pwm_set_clock(gpio, GPIO_PWM_CLOCK_DIV128);
    gpio_pwm_set_shift(gpio, 0);

    close(fd_gpio);
}

void gpio_pwm_set(int gpio, uint32_t duty_cycle) {
    uint32_t period = gpio_pwm_get_period(gpio);
    uint32_t pulse = duty_cycle * period / 100;

    gpio_pwm_set_run_state(gpio, 1);
    gpio_pwm_set_compare(gpio, GPIO_PWM_CHANNEL_0, pulse);
}

void log_data(uint16_t fan_speed, float temperature) {
    static uint16_t buffer[BUFFER_SIZE];
    static size_t index = 0;

    buffer[index++] = fan_speed;
    index %= BUFFER_SIZE;
    printf("Fan speed: %d, Temperature: %.2f°C\n", fan_speed, temperature);
}

int main() {
    struct i2c_data i2c;
    int gpio_fan = 18; // Assuming the fan is connected to GPIO18

    if (i2c_init(&i2c) < 0) {
        return 1;
    }

    gpio_pwm_setup(gpio_fan);

    while (1) {
        uint8_t data[2];
        i2c_read(&i2c, 0, data, sizeof(data));
        float temperature = (data[0] << 8 | data[1]) * 0.0625; // Converting raw data to temperature (°C)

        uint16_t fan_speed = 0;
        if (temperature > 60.0) {
            fan_speed = 100;
        } else if (temperature > 55.0) {
            fan_speed = 80;
        } else if (temperature > 50.0) {
            fan_speed = 60;
        } else if (temperature > 45.0) {
            fan_speed = 40;
        } else {
            fan_speed = 0;
        }

        gpio_pwm_set(gpio_fan, fan_speed);
        log_data(fan_speed, temperature);
        usleep(100000); // Sleep for 100ms
    }

    munmap(i2c.map, 32);
    close(i2c.file);

    return 0;
}
