#include <signal.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <wiringPi.h>

// Configuration
#define I2C_BUS 1
#define NUM_SENSORS 4
#define FAN_PIN 18 // GPIO18 (PWM0)
#define PWM_RANGE 100
#define TEMP_THRESHOLD_HIGH 60.0
#define TEMP_THRESHOLD_LOW 40.0
#define LOG_BUFFER_SIZE 100

// Data structure for logging
typedef struct {
    time_t timestamp;
    float temperature[NUM_SENSORS];
    int fan_speed;
} LogEntry;

// Global variables
int i2c_fds[NUM_SENSORS];
LogEntry log_buffer[LOG_BUFFER_SIZE];
int log_buffer_index = 0;
volatile sig_atomic_t program_running = 1;

// Function prototypes
float read_temperature(int fd);
void set_fan_speed(int speed);
void log_data(float temperatures[], int fan_speed);
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
}

// Function to read temperature from LM75B sensor
float read_temperature(int fd) {
    int raw_temp;
    float temperature;

    raw_temp = i2c_smbus_read_word_data(fd, 0x00); // Read temperature register
    if (raw_temp < 0) {
        fprintf(stderr, "Error reading temperature: %d\n", raw_temp);
        return -100.0; // Indicate error
    }

    // Convert raw temperature to Celsius
    temperature = (float)(raw_temp >> 4) * 0.0625;
    return temperature;
}

// Function to set fan speed using PWM
void set_fan_speed(int speed) {
    if (speed < 0) speed = 0;
    if (speed > PWM_RANGE) speed = PWM_RANGE;
    pwmWrite(FAN_PIN, speed);
}

// Function to log temperature, fan speed, and timestamp to circular buffer
void log_data(float temperatures[], int fan_speed) {
    time_t now = time(NULL);

    for (int i = 0; i < NUM_SENSORS; i++) {
        log_buffer[log_buffer_index].timestamp = now;
        log_buffer[log_buffer_index].temperature[i] = temperatures[i];
    }
    log_buffer[log_buffer_index].fan_speed = fan_speed;

    log_buffer_index = (log_buffer_index + 1) % LOG_BUFFER_SIZE;
}

int main() {
    int sensor_addresses[NUM_SENSORS] = {0x48, 0x49, 0x4A, 0x4B};
    float temperatures[NUM_SENSORS];
    int i;

    // Initialize wiringPi using GPIO numbering
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi\n");
        return 1;
    }

    // Initialize PWM on the fan pin
    pinMode(FAN_PIN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(PWM_RANGE);
    pwmSetClock(192); // Adjust for desired PWM frequency

    // Initialize I2C and open device files
    for (i = 0; i < NUM_SENSORS; i++) {
        i2c_fds[i] = open("/dev/i2c-1", O_RDWR);
        if (i2c_fds[i] < 0) {
            fprintf(stderr, "Error opening I2C device %d\n", i);
            return 1;
        }
        if (ioctl(i2c_fds[i], I2C_SLAVE, sensor_addresses[i]) < 0) {
            fprintf(stderr, "Error setting I2C slave address %d\n", sensor_addresses[i]);
            return 1;
        }
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Temperature monitoring and fan control started. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Read temperatures from all sensors
        for (i = 0; i < NUM_SENSORS; i++) {
            temperatures[i] = read_temperature(i2c_fds[i]);
            if (temperatures[i] < -99.0) { // Error occurred
                fprintf(stderr, "Error reading temperature from sensor %d\n", i);
            }
        }

        // Determine average temperature
        float avg_temp = 0.0;
        int valid_sensor_count = 0;
        for (i = 0; i < NUM_SENSORS; i++) {
            if (temperatures[i] > -99.0) { // Only include valid temperatures
                avg_temp += temperatures[i];
                valid_sensor_count++;
            }
        }
        avg_temp /= valid_sensor_count;

        // Control fan speed based on average temperature
        int fan_speed = 0;
        if (avg_temp > TEMP_THRESHOLD_HIGH) {
            fan_speed = PWM_RANGE;
        } else if (avg_temp < TEMP_THRESHOLD_LOW) {
            fan_speed = 0;
        } else {
            fan_speed = (int)((avg_temp - TEMP_THRESHOLD_LOW) / (TEMP_THRESHOLD_HIGH - TEMP_THRESHOLD_LOW) * PWM_RANGE);
        }

        // Set fan speed
        set_fan_speed(fan_speed);

        // Log data
        log_data(temperatures, fan_speed);

        // Print data to console
        printf("Average Temperature: %.2f C, Fan Speed: %d\n", avg_temp, fan_speed);

        sleep(5);
    }

    // Close I2C device files
    for (i = 0; i < NUM_SENSORS; i++) {
        close(i2c_fds[i]);
    }

    return 0;
}

