    pio = mmap(NULL, 4, PROT_READ | PROT_WRITE, MAP_SHARED, devMem2Phys(MEM_BASE + PIO_B), PIO_PHYS + (pioBase + PIO_B));

    if ((thermocouple_spi_fd = spiOpen(0, SPICLOCK_400000)) < 0) {
        perror("Failed to open SPI bus\n");
        exit(EXIT_FAILURE);
    }

    spi_transfers[0].tx_buf = (unsigned char *) &MAX31855_READ_TEMP;
    spi_transfers[0].rx_buf = (unsigned char *) malloc(4);
    spi_transfers[0].bits_per_word = 8;
    spi_transfers[0].delay_usecs = 0;
    spi_transfers[0].length = sizeof(MAX31855_READ_TEMP);
}

unsigned short readTemperature() {
    int ret;

    ret = spiXfer(thermocouple_spi_fd, spi_transfers, 1);
    if (ret != 1) {
        perror("Failed to read from SPI\n");
        return 0;
    }

    return (unsigned short) ((spi_transfers[0].rx_buf[1] << 8) | spi_transfers[0].rx_buf[0]);
}

void setFanSpeed(int speed) {
    int duty_cycle = (speed * (1000 / MAX_FAN_SPEED)) / 10;
    *((volatile unsigned int *)(pio + (fan_pin / 32) * 4 + ((fan_pin % 32) / 8) * 4 + (fan_pin % 8) * 4)) = duty_cycle;
