int main() {
    setup();

    int fan_speed = MIN_FAN_SPEED;
    double last_temp = 0;
    double current_temp;
    double temp_delta = 0;
    double fan_delta = 0;
    unsigned short temp;

    while (1) {
        current_temp = readTemperature() / 10.0;
        temp_delta = current_temp - last_temp;

        if (fabs(temp_delta) > 0.5) {
            last_temp = current_temp;

            if (current_temp > MAX_TEMP) {
                fan_speed += (current_temp - MAX_TEMP) * FAN_INTERVAL;
                if (fan_speed > MAX_FAN_SPEED) fan_speed = MAX_FAN_SPEED;
            } else if (current_temp < last_temp - 0.5) {
                fan_speed -= (last_temp - current_temp - 0.5) * FAN_INTERVAL;
                if (fan_speed < MIN_FAN_SPEED) fan_speed = MIN_FAN_SPEED;
