#define LOG_FILE "motion.log"

// Global variables
static volatile int running = 1;
static FILE *log_file = NULL;
static pthread_mutex_t log_mutex;

// Function prototypes
int initialize();
void cleanup();
void log_event(int pin, int level);
void handle_signal(int sig);
void alert_func(int gpio, int level, uint32_t tick, void *user);

// Structure to pass data to the alert function
typedef struct {
    int pin;
} sensor_data_t;

// Signal handler function
void handle_signal(int sig) {
    printf("Caught signal %d, exiting gracefully...\n", sig);
    running = 0;
}

// Alert function (called when GPIO state changes)
void alert_func(int gpio, int level, uint32_t tick, void *user) {
    sensor_data_t *data = (sensor_data_t*)user;
    log_event(data->pin, level);
}

// Function to log the event to a file
void log_event(int pin, int level) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    pthread_mutex_lock(&log_mutex);
    if (log_file != NULL) {
        fprintf(log_file, "%s - GPIO %d - %s\n", timestamp, pin, level == 1 ? "HIGH" : "LOW");
        fflush(log_file); // Ensure the data is written to the file immediately
    }
    pthread_mutex_unlock(&log_mutex);
}

// Function to initialize the pigpio library and GPIO pins
int initialize() {
    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }

    // Set GPIO pins as inputs with pull-down resistors (adjust as needed)
    gpioSetMode(PIR_PIN_1, PI_INPUT);
    gpioSetMode(PIR_PIN_2, PI_INPUT);
    gpioSetMode(PIR_PIN_3, PI_INPUT);

    // Set alert functions for each pin
    sensor_data_t sensor1_data = {PIR_PIN_1};
    sensor_data_t sensor2_data = {PIR_PIN_2};
    sensor_data_t sensor3_data = {PIR_PIN_3};

    gpioSetAlertFuncEx(PIR_PIN_1, alert_func, &sensor1_data);
    gpioSetAlertFuncEx(PIR_PIN_2, alert_func, &sensor2_data);
    gpioSetAlertFuncEx(PIR_PIN_3, alert_func, &sensor3_data);

    return 0; // Indicate success
}

// Function to cleanup the pigpio library and close the log file
void cleanup() {
    printf("Cleaning up...\n");

    // Stop alerts (optional, but good practice)
    gpioSetAlertFunc(PIR_PIN_1, NULL);
    gpioSetAlertFunc(PIR_PIN_2, NULL);
    gpioSetAlertFunc(PIR_PIN_3, NULL);

    // Terminate the pigpio library
    gpioTerminate();

    // Close the log file
    pthread_mutex_lock(&log_mutex);
    if (log_file != NULL) {
        fclose(log_file);
        log_file = NULL; // Prevent double closing
    }
    pthread_mutex_unlock(&log_mutex);
    pthread_mutex_destroy(&log_mutex);
}

int main() {
