    signal(SIGINT, handle_signal);
    signal(SIGTERM, handle_signal);

    // Initialize the logging mutex
    if (pthread_mutex_init(&log_mutex, NULL) != 0) {
        fprintf(stderr, "Mutex initialization failed\n");
        return 1;
    }

    // Open the log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
