Here's a simple C program for Raspberry Pi that uses the `wiringPi` library to detect motion via a PIR sensor on GPIO 4, logs timestamps of motion events to a "motion_log.txt" file, and handles potential `wiringPiSetup` failures. The program also ensures the file is properly opened and closed after each timestamp entry, formatted as "YYYY-MM-DD HH:MM:SS".

```c
#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <wiringPi.h>

#define PIR_PIN 4
#define LOG_FILE "motion_log.txt"

void log_timestamp(const char* message) {
    time_t rawtime;
    struct tm* timeinfo;
    char time_string[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(time_string, sizeof(time_string), "%Y-%m-%d %H:%M:%S", timeinfo);
    FILE* log_file = fopen(LOG_FILE, "a");
    if (log_file != NULL) {
        fprintf(log_file, "%s: %s\n", time_string, message);
        fclose(log_file);
    }
}

int main(void) {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Unable to start wiringPi: %s\n", wiringPiStatus());
        return 1;
    }

    pinMode(PIR_PIN, INPUT);
    pullUpDnControl(PIR_PIN, PUD_UP);

    int prev_state = digitalRead(PIR_PIN);

    while (1) {
        int state = digitalRead(PIR_PIN);
        if (state != prev_state) {
            log_timestamp("Motion detected");
            prev_state = state;
        }
        delay(1000);
    }

    return 0;
}
