To create a C program for Raspberry Pi 4 Model B using the pigpio library that triggers a buzzer connected to GPIO18 via an interrupt when a HC-SR501 PIR sensor connected to GPIO4 detects motion, logs each motion event (timestamp and duration of buzzer activation) to a file named 'motion_log.txt', follow the steps below:

1. Install the pigpio library if you haven't already:

```bash
sudo apt-get update
sudo apt-get install pigpio
```

2. Create a new C file named `motion_detector.c` and paste the following code into it:

```c
#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <unistd.h>
#include <string.h>
#include <fcntl.h>
#include <sys/stat.h>
#include <pigpio.h>

#define PIR_GPIO 4
#define BUZZER_GPIO 18
#define LOG_FILE "motion_log.txt"

volatile sig_atomic_t motion_detected = 0;

void pir_callback(int gpio, int level, uint32_t tick) {
    (void)tick;
    motion_detected = 1;
    gpiowrite(BUZZER_GPIO, 1);
}

void log_motion_event(const char *message) {
    time_t rawtime;
    struct tm *timeinfo;
    char time_string[80];
    int log_fd;

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(time_string, sizeof(time_string), "%Y-%m-%d %H:%M:%S", timeinfo);

    log_fd = open(LOG_FILE, O_WRONLY | O_APPEND | O_CREAT, S_IRUSR | S_IWUSR | S_IRGRP | S_IROTH);
    if (log_fd == -1) {
        perror("Error opening log file");
        return;
    }

    write(log_fd, time_string, strlen(time_string));
    write(log_fd, " - Motion detected - Duration: ", strlen(" - Motion detected - Duration: "));

    struct timespec start, end;
    clock_gettime(CLOCK_MONOTONIC, &start);

    while (motion_detected) {
        gpioread(BUZZER_GPIO);
        usleep(100000);
    }

    clock_gettime(CLOCK_MONOTONIC, &end);
    double duration = (end.tv_sec - start.tv_sec) + (end.tv_nsec - start.tv_nsec) / 1_ billion;
    write(log_fd, format("%.3f s\n", duration), strlen(format("%.3f s\n", duration)));

    close(log_fd);
}

int main(void) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Failed to initialise pigpio library\n");
        return 1;
    }

    if (gpioSetMode(PIR_GPIO, PI_INPUT) < 0 || gpioSetPullUpDown(PIR_GPIO, PI_PUD_UP) < 0) {
        fprintf(stderr, "Failed to set PIR sensor GPIO mode\n");
        return 1;
    }

    if (gpioSetAlertFunc(PIR_GPIO, pir_callback) < 0) {
        fprintf(stderr, "Failed to set PIR sensor alert function\n");
        return 1;
    }

    if (gpioInitialise() < 0) {
        fprintf(stderr, "Failed to initialise pigpio library\n");
        return 1;
    }

    if (gpioSetMode(BUZZER_GPIO, PI_OUTPUT) < 0) {
        fprintf(stderr, "Failed to set buzzer GPIO mode\n");
        return 1;
    }

    gpiowrite(BUZZER_GPIO, 0);

    while (1) {
        usleep(100000);
        if (motion_detected) {
            log_motion_event("");
            motion_detected = 0;
        }
    }

    gpioTerminate();
    return 0;
}
