// Initializes a PIRSensor
PIRSensor* PIRSensor_init(int gpio) {
    PIRSensor* sensor = (PIRSensor*)malloc(sizeof(PIRSensor));
    if (sensor == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return NULL;
    }
    sensor->gpio = gpio;
    gpioSetMode(gpio, PI_INPUT); // Set GPIO as input
    gpioSetPullUpDown(gpio, PI_PUD_DOWN); // Enable pull-down resistor
    return sensor;
}

// Reads the current state of the PIR sensor
int PIRSensor_readSensor(PIRSensor* sensor) {
    return gpioRead(sensor->gpio);
}

// Initializes a Buzzer
Buzzer* Buzzer_init(int gpio) {
    Buzzer* buzzer = (Buzzer*)malloc(sizeof(Buzzer));
    if (buzzer == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return NULL;
    }
    buzzer->gpio = gpio;
    gpioSetMode(gpio, PI_OUTPUT); // Set GPIO as output
    return buzzer;
}

// Activates the buzzer
void Buzzer_activate(Buzzer* buzzer) {
    gpioWrite(buzzer->gpio, 1); // Set GPIO to high (activate buzzer)
}

// Deactivates the buzzer
void Buzzer_deactivate(Buzzer* buzzer) {
    gpioWrite(buzzer->gpio, 0); // Set GPIO to low (deactivate buzzer)
}

