#include <stdio.h>
#include <pigpio.h>
#include <signal.h>
#include <stdlib.h>
#include <unistd.h>
#include <stdbool.h>

// Define GPIO pins for sensors and servo
#define TRIG_FRONT 4
#define ECHO_FRONT 17
#define TRIG_LEFT 27
#define ECHO_LEFT 22
#define TRIG_RIGHT 23
#define ECHO_RIGHT 24
#define SERVO_PIN 18

#define MAX_DISTANCE 200 // Maximum measurable distance in cm
#define ERROR_VALUE -1    // Error value for distance measurement
#define OBSTACLE_THRESHOLD 30 // Obstacle detection threshold in cm

// Structure to store sensor data
typedef struct {
    int angle;
    float front_distance;
    float left_distance;
    float right_distance;
} SensorData;

// Global variable to indicate program termination
volatile sig_atomic_t program_running = 1;

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    (void)signal; // Suppress unused parameter warning
    program_running = 0;
    printf("\nProgram terminated by user.\n");
}

// Function to initialize GPIO pins
int init_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }

    // Set GPIO modes for trigger and echo pins
    gpioSetMode(TRIG_FRONT, PI_OUTPUT);
    gpioSetMode(ECHO_FRONT, PI_INPUT);
    gpioSetMode(TRIG_LEFT, PI_OUTPUT);
    gpioSetMode(ECHO_LEFT, PI_INPUT);
    gpioSetMode(TRIG_RIGHT, PI_OUTPUT);
    gpioSetMode(ECHO_RIGHT, PI_INPUT);
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    // Initialize trigger pins to low
    gpioWrite(TRIG_FRONT, 0);
    gpioWrite(TRIG_LEFT, 0);
    gpioWrite(TRIG_RIGHT, 0);

    // Set servo to 0 degrees initially
    set_servo_angle(0);

    return 0; // Indicate success
}

// Function to set the servo angle
void set_servo_angle(int angle) {
    // Ensure angle is within valid range
    if (angle < 0) angle = 0;
    if (angle > 180) angle = 180;

    // Convert angle to pulse width (SG90 servo: 500us - 2500us for 0-180 degrees)
    int pulse_width = 500 + (int)((float)angle / 180.0 * 2000.0);
    gpioServo(SERVO_PIN, pulse_width); // Set servo position
    gpioDelay(20); //Allow servo to move
}

// Function to measure distance using HC-SR04 sensor
float get_distance(int trig_pin, int echo_pin) {
    // Trigger the sensor
    gpioWrite(trig_pin, 1);
    gpioDelay(10); //10us trigger pulse
    gpioWrite(trig_pin, 0);

    // Measure echo pulse duration
    uint32_t start_tick = gpioTick();
    uint32_t end_tick = start_tick;

    // Wait for echo pin to go high (with timeout)
    int timeout = 10000; // Timeout after 10ms
    while (gpioRead(echo_pin) == 0 && timeout > 0) {
        timeout--;
        gpioDelay(1);
    }

    if (timeout <= 0) {
        fprintf(stderr, "Timeout waiting for echo high\n");
        return ERROR_VALUE; // Timeout error
    }

    start_tick = gpioTick();

    // Wait for echo pin to go low (with timeout)
    timeout = 10000;
    while (gpioRead(echo_pin) == 1 && timeout > 0) {
        timeout--;
        gpioDelay(1);
    }

    if (timeout <= 0) {
        fprintf(stderr, "Timeout waiting for echo low\n");
        return ERROR_VALUE; // Timeout error
    }

    end_tick = gpioTick();

    // Calculate pulse duration in microseconds
    uint32_t pulse_duration = end_tick - start_tick;

    // Calculate distance in centimeters (speed of sound: 343 m/s)
    // distance = (pulse_duration * 0.000001) * 34300 / 2;
    float distance = (float)pulse_duration / 1000000.0 * 34300.0 / 2.0;

    // Filter out invalid distances
    if (distance > MAX_DISTANCE) {
        return MAX_DISTANCE; // Return max distance if out of range
    }

    return distance;
}

// Function to check if an obstacle is nearby
bool is_obstacle_nearby(float distance) {
    return (distance != ERROR_VALUE && distance < OBSTACLE_THRESHOLD);
}

// Function to process scan data and trigger alerts
void process_scan_data(int angle, float front_distance, float left_distance, float right_distance) {
    if (is_obstacle_nearby(front_distance)) {
        printf("WARNING: Obstacle detected in front at angle %d, distance: %.2f cm\n", angle, front_distance);
    }
    if (is_obstacle_nearby(left_distance)) {
        printf("WARNING: Obstacle detected on the left at angle %d, distance: %.2f cm\n", angle, left_distance);
    }
    if (is_obstacle_nearby(right_distance)) {
        printf("WARNING: Obstacle detected on the right at angle %d, distance: %.2f cm\n", angle, right_distance);
    }
}

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (init_gpio() != 0) {
        return 1; // Exit if initialization fails
    }

    printf("Drone navigation system started. Press Ctrl+C to exit.\n");

    // Main loop for scanning and obstacle detection
    int angle;
    while (program_running) {
        for (angle = 0; angle <= 180; angle += 10) {
            set_servo_angle(angle);

            // Measure distances from all three sensors
            float front_distance = get_distance(TRIG_FRONT, ECHO_FRONT);
            float left_distance = get_distance(TRIG_LEFT, ECHO_LEFT);
            float right_distance = get_distance(TRIG_RIGHT, ECHO_RIGHT);

            // Process the scan data
            process_scan_data(angle, front_distance, left_distance, right_distance);

            gpioDelay(100); // Delay between readings
        }
    }

    // Clean up GPIO resources before exiting
    set_servo_angle(0); // Set servo to a safe position
    gpioTerminate();

    return 0;
}

