To create a parking assist system using a Raspberry Pi Zero W, HC-SR04 ultrasonic sensor, SG90 servo motor, and the `pigpio` library, follow the steps below:

1. First, install the `pigpio` library on your Raspberry Pi by running the following commands:

```bash
sudo apt-get update
sudo apt-get install pigpio
```

2. Create a new C file named `parking_assist.c` and paste the following code:

```c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <pigpio.h>

#define TRIG_PIN 17
#define ECHO_PIN 18
#define SERVO_PIN 27
#define ALERT_PIN 22
#define MIN_DISTANCE 30
#define SERVO_MIN_ANGLE 0
#define SERVO_MAX_ANGLE 180
#define SERVO_STEP 1
#define TIMEOUT 5000
#define DEG_TO_US (58.25) // Conversion factor for servo angles to microseconds

static int pi;

void servo_set_angle(int angle) {
    int us = (angle - SERVO_MIN_ANGLE) * DEG_TO_US / (SERVO_MAX_ANGLE - SERVO_MIN_ANGLE);
    gpioWrite(SERVO_PIN, (us > 1000) ? 1 : 0);
    usleep(us);
    gpioWrite(SERVO_PIN, 0);
}

float get_distance() {
    gpioWrite(TRIG_PIN, 1);
    usleep(1000);
    gpioWrite(TRIG_PIN, 0);
    unsigned long start = timeUs();
    while ((gpioRead(ECHO_PIN) == 0) && (timeUs() - start < TIMEOUT));
    unsigned long start_echo = timeUs();
    while ((gpioRead(ECHO_PIN) == 1) && (timeUs() - start_echo < TIMEOUT));
    float distance = (timeUs() - start_echo) / 2 * 340.0 / 1000.0;
    return distance;
}

void alert() {
    gpioWrite(ALERT_PIN, 1);
    usleep(100000);
    gpioWrite(ALERT_PIN, 0);
}

int main(int argc, char *argv[]) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Failed to initialize pigpio\n");
        return 1;
    }

    pi = pigpio;

    gpioSetMode(TRIG_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(SERVO_PIN, PI_OUTPUT);
    gpioSetMode(ALERT_PIN, PI_OUTPUT);

    servo_set_angle(SERVO_MIN_ANGLE);

    float distance = get_distance();
    while (1) {
        distance = get_distance();
        if (distance < MIN_DISTANCE) {
            printf("Object detected at %f cm!\n", distance);
            alert();
        } else {
            printf("No object detected at %f cm\n", distance);
        }

        servo_set_angle(servo_getAngle() + SERVO_STEP);
        usleep(100000); // Delay between servo angle changes
    }

    gpioTerminate();
    return 0;
}
```

3. Compile the program with the following command:

```bash
gcc parking_assist.c -o parking_assist -lwiringPi -lpthread -lrt -lpigpio
```

4. Run the compiled program with the following command:

```bash
sudo ./parking_assist
```

