#include <unistd.h>

// Define GPIO pins
#define TRIGGER_PIN 4
#define ECHO_PIN 17
#define SERVO_PIN 18

// Constants
#define SPEED_OF_SOUND 34300.0 // cm/s
#define DISTANCE_THRESHOLD 30.0 // cm

// Global variables
volatile sig_atomic_t terminate = 0;

// Signal handler for Ctrl+C
void signalHandler(int signum) {
    terminate = 1;
    fprintf(stderr, "\nCaught signal %d, terminating gracefully...\n", signum);
}

// Function to measure distance using HC-SR04
float measureDistance() {
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10); // 10us trigger pulse
    gpioWrite(TRIGGER_PIN, 0);

    long long startTick, endTick;

    // Wait for echo to start
    int count = 0;
    while (gpioRead(ECHO_PIN) == 0 && count < 10000) {
        gpioDelay(1); // Small delay to prevent busy-waiting
        count++;
    }
    if (count >= 10000) return -1.0; // Timeout
    startTick = gpioTick();

    // Wait for echo to end
    count = 0;
    while (gpioRead(ECHO_PIN) == 1 && count < 10000) {
        gpioDelay(1);
        count++;
    }
    if (count >= 10000) return -1.0; // Timeout
    endTick = gpioTick();

    long long pulseWidth = endTick - startTick;

    if (pulseWidth <= 0) {
        return -1.0; // Error: Invalid pulse width
    }

    float distance = (pulseWidth * SPEED_OF_SOUND) / 2000000.0; // Convert to cm
    return distance;
}

// Function to set servo angle
void setServoAngle(int angle) {
    if (angle < 0 || angle > 180) {
        fprintf(stderr, "Error: Servo angle out of range (0-180).\n");
        return;
    }
    int pulseWidth = 500 + (angle * 2000 / 180); // Map angle to pulse width (500-2500)
    gpioServo(SERVO_PIN, pulseWidth);
}

// Function to process servo sweep and display distance readings
void processServoSweep() {
    for (int angle = 0; angle <= 180; angle += 10) {
        setServoAngle(angle);
        gpioDelay(100); // Delay for servo to settle

        float distance = measureDistance();
        if (distance < 0) {
            fprintf(stderr, "Error: Distance measurement failed.\n");
            continue; // Skip to the next angle
        }

        printf("Angle: %d degrees, Distance: %.2f cm\n", angle, distance);

        if (distance <= DISTANCE_THRESHOLD) {
            printf("Alert: Object detected within threshold!\n");
        }
    }
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    // Register signal handler
    signal(SIGINT, signalHandler);

    printf("Parking assist system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (!terminate) {
        processServoSweep();
    }

    // Clean up
    gpioTerminate();
    printf("Program terminated.\n");
    return 0;
}

