#define SHT31_ADDR 0x44
#define MEASURE_COMMAND 0x2400

int i2c_fd;
FILE *fp;
volatile sig_atomic_t stop_flag = 0;

void signal_handler(int sig) {
    printf("Caught signal %d, exiting gracefully.\n", sig);
    stop_flag = 1;
}

/* Function to read temperature and humidity from SHT31-D */
int read_sht31d(float *temperature, float *humidity) {
    unsigned char data[6];
    int raw_temperature, raw_humidity;

    // Send measurement command
    if (wiringPiI2CWriteReg16(i2c_fd, 0x00, MEASURE_COMMAND) < 0) {
        perror("Error writing measurement command");
        return -1;
    }

    delay(20); // Wait for measurement (datasheet specifies 15ms)

    // Read 6 bytes of data
    if (read(i2c_fd, data, 6) != 6) {
        perror("Error reading data");
        return -2;
    }

    // Convert raw data to temperature and humidity
    raw_temperature = (data[0] << 8) | data[1];
    raw_humidity = (data[3] << 8) | data[4];

    *temperature = -45.0 + (175.0 * raw_temperature / 65535.0);
    *humidity = 100.0 * raw_humidity / 65535.0;

    return 0;
}

/* Function to get the current timestamp in ISO 8601 format */
char* get_timestamp() {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    static char timestamp[32]; // Static buffer to avoid memory allocation issues
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%dT%H:%M:%SZ", t);
    return timestamp;
}

/* Function to format data as JSON */
char* format_json(float temperature, float humidity, char *timestamp) {
    static char json_string[256]; // Static buffer
    snprintf(json_string, sizeof(json_string), "{\"temperature\": %.2f, \"humidity\": %.2f, \"timestamp\": \"%s\"}\n", temperature, humidity, timestamp);
    return json_string;
}

/* Function to write data to file */
int write_to_file(char *json_string) {
    if (fputs(json_string, fp) == EOF) {
        perror("Error writing to file");
        return -1;
    }
    fflush(fp); // Ensure data is written immediately
    return 0;
}

int main() {
    float temperature, humidity;
    char *timestamp, *json_string;

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed\n");
        return 1;
    }

    // Initialize I2C
    i2c_fd = wiringPiI2CSetup(SHT31_ADDR);
    if (i2c_fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed\n");
        return 1;
    }

    // Open file for writing
    fp = fopen("environmental_data.json", "a");
    if (fp == NULL) {
        perror("Error opening file");
        return 1;
    }

    // Set up signal handling
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Starting data logging...\n");

    while (!stop_flag) {
        // Read sensor data
        if (read_sht31d(&temperature, &humidity) == 0) {
            // Get timestamp
            timestamp = get_timestamp();

            // Format as JSON
