    send_command(file, 0x40);
    send_command(file, 0x00);
    send_command(file, 0xA4);
    send_command(file, 0xA6);
    send_command(file, 0xAF);

    usleep(1000);
}

void draw_time(int file, time_t rawtime) {
    struct tm *timeinfo = localtime(&rawtime);
    char time_str[9];
    strftime(time_str, sizeof(time_str), "%H:%M:%S", timeinfo);

    unsigned char hour[4] = {0x30 + timeinfo->tm_hour / 10, 0x30 + timeinfo->tm_hour % 10};
    unsigned char minute[4] = {0x30 + timeinfo->tm_min / 10, 0x30 + timeinfo->tm_min % 10};
    unsigned char second[4] = {0x30 + timeinfo->tm_sec / 10, 0x30 + timeinfo->tm_sec % 10};

