#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <fcntl.h>
#include <wiringPiI2C.h>

#define VL53L1X_I2C_ADDR 0x29  // Replace with the correct I2C address
#define SAMPLE_INTERVAL_MS 50
#define WARNING_DISTANCE 200  // Object warning threshold in millimeters
#define LOG_FILE "distance_log.txt"

int main() {
    int file;
    FILE *logFile;
    int fd = wiringPiI2CSetup(VL53L1X_I2C_ADDR);
    if (fd < 0) {
        printf("Failed to open I2C connection to VL53L1X.\n");
        return 1;
    }

    logFile = fopen(LOG_FILE, "w");
    if (logFile == NULL) {
        printf("Failed to open log file.\n");
        return 1;
    }

    unsigned char meas_mode = 0x81;
    unsigned char start_range_msb = 0x01;
    unsigned char start_range_lsb = 0x40;
    unsigned char start_measurement = 0x00;

    // Set measurement mode
    wiringPiI2CWriteReg8(fd, 0x80, meas_mode);
    usleep(100000);  // Delay for 100 ms

    // Start range measurement
    wiringPiI2CWriteReg8(fd, 0x94, start_range_msb);
    wiringPiI2CWriteReg8(fd, 0x95, start_range_lsb);
    wiringPiI2CWriteReg8(fd, 0x96, start_measurement);

    unsigned short range_mm;
    while (1) {
        usleep(SAMPLE_INTERVAL_MS * 1000);  // Wait for the specified sample interval

        // Read range data (16-bit 2's complement)
        unsigned char high = wiringPiI2CReadReg8(fd, 0x83);
        unsigned char low = wiringPiI2CReadReg8(fd, 0x84);

        // Convert the data to a signed 16-bit value
        short range_raw = (short)(high << 8 | low);
        range_mm = (unsigned short)((range_raw * 25 / 16) - 50);  // Convert to millimeters and offset

        // Log the timestamp and distance
        time_t now = time(NULL);
        char timestamp[20];
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", localtime(&now));
        fprintf(logFile, "%s, %d\n", timestamp, range_mm);

        if (range_mm < WARNING_DISTANCE) {
            printf("Warning: Object detected at %d mm\n", range_mm);
        }
    }

    fclose(logFile);
    return 0;
}
