        return -1;
    }

    *i2c_fd = pigpio_i2c_open(0, AHT20_ADDR, &err);
    if (*i2c_fd < 0) {
        fprintf(stderr, "Failed to open I2C connection to AHT20 (err=%d)\n", err);
        return -1;
    }

    return 0;
}

