    char cmd[] = {0x2B, 0x03, 0x00, 0x00, 0x00};
    char resp[6];
    int ret;

    cmd[2] = (char)(16 << 4 | 0x28); // Select Humidity and Temperature Measurements

    ret = pigpio_i2c_write_read(i2c_fd, cmd, 5, resp, 6);
    if (ret != 6) {
        fprintf(stderr, "Failed to read from AHT20 (ret=%d)\n", ret);
        return -1;
    }

