    i2c_handle = i2cOpen(I2C_BUS, AHT20_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C bus: %d\n", i2c_handle);
        return 1;
    }

    // Send initialization command
    char init_cmd[3] = {0xBE, 0x08, 0x00};
    int result = i2cWriteDevice(i2c_handle, init_cmd, 3);
    if (result != 3) {
        fprintf(stderr, "Failed to send initialization command: %d\n", result);
        return 1;
    }

    // Wait for 80 milliseconds
    gpioDelay(80000); // Delay in microseconds

    return 0;
}

// Read temperature and humidity data from the AHT20 sensor
int aht20_read_data(float *temperature, float *humidity) {
    char measure_cmd[3] = {0xAC, 0x33, 0x00};
    char data[6];

    // Send measurement command
    int result = i2cWriteDevice(i2c_handle, measure_cmd, 3);
    if (result != 3) {
        fprintf(stderr, "Failed to send measurement command: %d\n", result);
        return 1;
    }

    // Wait for 80 milliseconds
    gpioDelay(80000); // Delay in microseconds

    // Read 6 bytes of data
    result = i2cReadDevice(i2c_handle, data, 6);
    if (result != 6) {
        fprintf(stderr, "Failed to read data: %d\n", result);
        return 1;
    }

    // Check status bit
    if (data[0] & 0x80) {
        fprintf(stderr, "Sensor busy\n");
        return 1;
    }

    // Calculate humidity and temperature
    unsigned long humidity_raw = ((unsigned long)data[1] << 12) | ((unsigned long)data[2] << 4) | (data[3] >> 4);
    unsigned long temperature_raw = ((unsigned long)data[3] & 0x0F) << 16 | ((unsigned long)data[4] << 8) | data[5];

    *humidity = ((float)humidity_raw / 0x100000) * 100;
    *temperature = ((float)temperature_raw / 0x100000) * 200 - 50;

    return 0;
}

// Control the cooling fan based on humidity
void control_fan(float humidity) {
    if (humidity > HUMIDITY_THRESHOLD) {
        gpioWrite(FAN_PIN, 1); // Turn fan on
    } else {
        gpioWrite(FAN_PIN, 0); // Turn fan off
    }
}

// Cleanup function to terminate pigpio and close I2C
void cleanup() {
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    gpioTerminate();
}

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    printf("Ctrl+C pressed, exiting gracefully...\n");
    cleanup();
    exit(0);
