// Define GPIO pins for the relays
#define DOOR_UP_PIN 1
#define DOOR_DOWN_PIN 4

// Define the log file name
#define LOG_FILE "door_log.txt"

// Global variable to track the door state
int door_state = 0; // 0 = closed, 1 = open

// Function prototypes
int initialize_gpio(void);
int control_door(int state);
int log_door_status(int state);
void cleanup_handler(int signum);

// Signal handler for graceful shutdown
void cleanup_handler(int signum) {
    printf("\nCaught signal %d, cleaning up...\n", signum);
    control_door(0); // Close the door
    delay(100);       // Give the relays time to switch
    exit(0);
}

// Initializes the wiringPi library and sets the GPIO pins as output
int initialize_gpio(void) {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return -1;
    }

    pinMode(DOOR_UP_PIN, OUTPUT);
    pinMode(DOOR_DOWN_PIN, OUTPUT);

    // Initially, both relays are OFF (LOW)
    digitalWrite(DOOR_UP_PIN, LOW);
    digitalWrite(DOOR_DOWN_PIN, LOW);

    return 0;
}

// Controls the chicken coop door by setting the specified GPIO pin HIGH to open and LOW to close
int control_door(int state) {
    if (state != 0 && state != 1) {
        fprintf(stderr, "Error: Invalid door state: %d\n", state);
        return -1;
    }

    digitalWrite(DOOR_UP_PIN, (state == 1) ? HIGH : LOW);
    digitalWrite(DOOR_DOWN_PIN, (state == 1) ? LOW : HIGH);

    // Update the global door state
    door_state = state;

    return 0;
}

// Logs the door status to a file with a timestamp
int log_door_status(int state) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return -1;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fprintf(fp, "%s: Door %s\n", timestamp, (state == 1) ? "is open" : "is closed");
    fclose(fp);

    return 0;
}

int main(void) {
    // Set up signal handling for Ctrl+C
    signal(SIGINT, cleanup_handler);

    // Initialize GPIO
    if (initialize_gpio() == -1) {
        return 1;
    }

    printf("Chicken coop door control system started.\n");
    printf("Press 'u' to open the door, 'c' to close it, or 'q' to quit.\n");

    char input;
    while (1) {
        printf("Enter command: ");
        scanf(" %c", &input);

        switch (input) {
            case 'u':
                if (control_door(1) == 0) {
