#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <wiringPiI2C.h>
#include <wiringPi.h>
#include <unistd.h>

// OLED display dimensions
#define OLED_WIDTH 128
#define OLED_HEIGHT 64

// I2C address of the OLED display
#define OLED_ADDR 0x3C

// OLED command constants
#define OLED_CMD_SET_CONTRAST 0x81
#define OLED_CMD_DISPLAY_ALL_ON_RESUME 0xA4
#define OLED_CMD_DISPLAY_ALL_ON 0xA5
#define OLED_CMD_NORMAL_DISPLAY 0xA6
#define OLED_CMD_INVERT_DISPLAY 0xA7
#define OLED_CMD_DISPLAY_OFF 0xAE
#define OLED_CMD_DISPLAY_ON 0xAF
#define OLED_CMD_SET_DISPLAY_OFFSET 0xD3
#define OLED_CMD_SET_COM_PINS 0xDA
#define OLED_CMD_SET_VCOM_DETECT 0xDB
#define OLED_CMD_SET_DISPLAY_CLOCK_DIV 0xD5
#define OLED_CMD_SET_PRECHARGE 0xD9
#define OLED_CMD_SET_COM_SCAN_DIR 0xC8 // Flip vertically
#define OLED_CMD_SET_SEGMENT_REMAP 0xA1 // Flip horizontally
#define OLED_CMD_CHARGE_PUMP 0x8D

#define OLED_CMD_SET_COLUMN_ADDR 0x21
#define OLED_CMD_SET_PAGE_ADDR 0x22
#define OLED_CMD_SET_MULTIPLEX_RATIO 0xA8

// Global variable for the I2C file descriptor
int fd;

// Function to send a command to the OLED display
void oled_command(uint8_t command) {
    wiringPiI2CWriteReg8(fd, 0x00, command);
}

// Function to send data to the OLED display
void oled_data(uint8_t data) {
    wiringPiI2CWriteReg8(fd, 0x40, data);
}

void oled_set_area()
{
    oled_command(OLED_CMD_SET_COLUMN_ADDR);
    oled_command(0);
    oled_command(OLED_WIDTH - 1);

    oled_command(OLED_CMD_SET_PAGE_ADDR);
    oled_command(0);
    oled_command((OLED_HEIGHT / 8) - 1);

}

// Function to initialize the OLED display
void oled_init() {
    oled_command(OLED_CMD_DISPLAY_OFF);
    oled_command(OLED_CMD_SET_DISPLAY_CLOCK_DIV);
    oled_command(0x80); // Suggested ratio
    oled_command(OLED_CMD_SET_MULTIPLEX_RATIO);
    oled_command(OLED_HEIGHT - 1);
    oled_command(OLED_CMD_SET_DISPLAY_OFFSET);
    oled_command(0x00);
    oled_command(OLED_CMD_CHARGE_PUMP);
    oled_command(0x14); // Enable charge pump
    oled_command(OLED_CMD_SET_SEGMENT_REMAP);  //Mirror
    oled_command(OLED_CMD_SET_COM_SCAN_DIR);
    oled_command(OLED_CMD_SET_COM_PINS);
    oled_command(0x12);
    oled_command(OLED_CMD_SET_CONTRAST);
    oled_command(0xCF);
    oled_command(OLED_CMD_SET_PRECHARGE);
    oled_command(0xF1);
    oled_command(OLED_CMD_SET_VCOM_DETECT);
    oled_command(0x40);
    oled_command(OLED_CMD_DISPLAY_ALL_ON_RESUME);
    oled_command(OLED_CMD_NORMAL_DISPLAY);
    oled_command(OLED_CMD_DISPLAY_ON);

    // Optionally clear the screen after initialization
    oled_set_area();
    for (int i = 0; i < (OLED_WIDTH * OLED_HEIGHT) / 8; i++) {
        oled_data(0x00); // Clear screen data
    }
}

// Function to fill the screen with white pixels
void oled_fill_white() {
    oled_set_area();
    for (int i = 0; i < (OLED_WIDTH * OLED_HEIGHT) / 8; i++) {
        oled_data(0xFF); // Set all pixels to white
    }
}




int main() {
    // Initialize WiringPi I2C
    wiringPiSetup();
    fd = wiringPiI2CSetup(OLED_ADDR);
    if (fd == -1) {
        printf("Error: Could not initialize I2C.\n");
        return 1;
    }

    // Initialize the OLED display
    oled_init();

    // Fill the screen with white pixels
    oled_fill_white();

    printf("OLED display should be fully white. Check the screen.\n");

    return 0;
}

