To create a C program for Raspberry Pi using WiringPi to initialize an SSD1306 OLED display via I2C communication, clear the screen, and display a fully white screen for testing, follow the steps below. First, make sure you have the required libraries installed:

1. Install WiringPi:

```bash
sudo apt-get update
sudo apt-get install wiringpi
```

2. Create a new file named `ssd1306_test.c` and paste the following code:

```c
#include <stdio.h>
#include <unistd.h>
#include <fcntl.h>
#include <linux/i2c-dev.h>
#include <sys/ioctl.h>
#include <wiringPiI2C.h>

#define SSD1306_I2C_ADDR 0x3C
#define SSD1306_WIDTH 128
#define SSD1306_HEIGHT 64

int init_ssd1306() {
    int file;
    if ((file = wiringPiI2CSetup(SSD1306_I2C_ADDR)) < 0) {
        printf("Failed to open I2C device.\n");
        return -1;
    }

    // Set display off
    write_cmd(file, 0xAE);

    // Set display on
    write_cmd(file, 0xAF);

    // Set display offset
    write_cmd(file, 0xD3);
    write_data(file, 0x00); // Display offset: 0x00, 0x10, 0x20, 0x30 or 0x40
    write_data(file, 0x40);

    // Set display start line
    write_cmd(file, 0x40);
    write_data(file, 0x00); // Set display start line: 0x00-0x3F
    write_data(file, 0x10);

    // Set segment remap
    write_cmd(file, 0xA0);
    write_cmd(file, 0xA1);

    // Set com output scan direction
    write_cmd(file, 0xC8);

    // Set display contrast
    write_cmd(file, 0x8D);
    write_data(file, 0x80); // Set display contrast: 0x20-0xAF

    // Set multiplex ratio
    write_cmd(file, 0xA8);
    write_data(file, 0x3F); // Set multiplex ratio: 0x20-0x3F

    // Set display on, no inversion
    write_cmd(file, 0xD5);
    write_data(file, 0x01);

    // Set display clock divide ratio
    write_cmd(file, 0xD9);
    write_data(file, 0xF1); // Set display clock divide ratio: 0x22-0xF1

    // Set pre-charge period
    write_cmd(file, 0xDA);
    write_data(file, 0x22); // Set pre-charge period: 0x14-0x22

    // Set COM pins hardware configuration
    write_cmd(file, 0xDB);
    write_data(file, 0x20); // Set COM pins hardware configuration: 0x00-0x4F

    // Set COM pins hardware configuration
    write_cmd(file, 0x81);
    write_data(file, 0x7F); // Set COM pins hardware configuration: 0x20-0xAF

    // Set segment pins hardware configuration
    write_cmd(file, 0x8D);
    write_data(file, 0x14); // Set segment pins hardware configuration: 0x0F-0x14

    // Set normal display
    write_cmd(file, 0xA4);
    write_cmd(file, 0xA6);

    // Set multiplex ratio
    write_cmd(file, 0xA8);
    write_data(file, 0x3F);

    // Set display on, no inversion
    write_cmd(file, 0xD5);
    write_data(file, 0x01);

    // Set display on, no inversion
    write_cmd(file, 0xAF);

    return file;
}

void write_cmd(int file, uint8_t cmd) {
    WiringPi::i2cWriteReg8(file, 0x00, cmd << 8 | 0x00);
}

void write_data(int file, uint8_t data) {
    WiringPi::i2cWriteReg8(file, 0x40, data << 8 | 0x00);
}

void clear_screen(int file) {
    for (int y = 0; y < SSD1306_HEIGHT; y++) {
        for (int x = 0; x < SSD1306_WIDTH; x++) {
            write_data(file, 0xFF);
        }
        usleep(5000);
    }
}

int main() {
    int file;

    if ((file = init_ssd1306()) < 0) {
        return 1;
    }

    clear_screen(file);

    printf("SSD1306 OLED display test successfully initialized!\n");

    usleep(50000000); // Sleep for 50ms

    return 0;
}
```

3. Compile the code:

```bash
gcc ssd1306_test.c -o ssd1306_test -lwiringPi
```

4. Run the compiled program:

```bash
sudo ./ssd1306_test
```

This program initializes the SSD1306 OLED display connected to the Raspberry Pi via I2C communication, clears the screen, and displays a fully white screen for testing.

