To create a C program for Raspberry Pi that blinks an LED connected to GPIO pin 18 every 2 seconds, and stops blinking when a button connected to GPIO pin 27 is pressed, you'll need to install the pigpio library first. You can do this by running the following commands in the terminal:

```bash
sudo apt-get update
sudo apt-get install pigpio
```

After installing the pigpio library, create a new file called `led_blink.c` and add the following code:

```c
#include <stdio.h>
#include <unistd.h>
#include <pigpio.h>

#define LED_PIN 18
#define BUTTON_PIN 27

void setup() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Failed to start pigpio\n");
        return;
    }

    gpioSetMode(LED_PIN, PI_OUTPUT);
    gpioSetMode(BUTTON_PIN, PI_INPUT);
    gpioSetPullUp(BUTTON_PIN);
}

void loop() {
    if (gpioRead(BUTTON_PIN) == GPIO_PIN_HIGH) {
        printf("Button pressed. Stopping LED blink.\n");
        gpioTerm();
        exit(0);
    }

    gpioWrite(LED_PIN, GPIO_HIGH);
    sleep(1);
    gpioWrite(LED_PIN, GPIO_LOW);
    sleep(1);
}

int main() {
    setup();

    while (1) {
        loop();
    }

    gpioTerm();
    return 0;
}
```

