// Configuration
const int NUM_SENSORS = 2;                                  // Number of soil moisture sensors
const int SENSOR_PINS[2] = {4, 17};                // GPIO pins for sensors
const int RELAY_PINS[2] = {27, 22};                 // GPIO pins for relays
const float MOISTURE_THRESHOLD = 30.0f;                    // Moisture threshold (%) for relay activation
const int SAMPLING_DELAY_MS = 100;                           // Delay between sensor readings (milliseconds)
const char* LOG_FILE_PREFIX = "soil_moisture_sensor"; // Prefix for log file names

// Function prototypes
int read_sensor(int gpio_pin);
float convert_to_moisture(int sensor_value);
void control_relay(int gpio_pin, float moisture_level);
void log_data(int sensor_index, int sensor_value, float moisture_level);
void cleanup(int signum);

// File pointers for logging (avoiding global variables)
FILE* log_files[2];

// Flag for graceful shutdown
volatile sig_atomic_t terminate = 0;

// Signal handler
void signal_handler(int signum) {
    terminate = 1;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure clock for better ADC accuracy
    gpioCfgClock(5, 1, 0); // 5us sample rate

    // Set GPIO modes for sensors and relays
    for (int i = 0; i < NUM_SENSORS; ++i) {
        gpioSetMode(SENSOR_PINS[i], PI_INPUT); // Sensors as input
        gpioSetMode(RELAY_PINS[i], PI_OUTPUT); // Relays as output
        gpioWrite(RELAY_PINS[i], 1);           // Initialize relays to OFF (HIGH)

        // Create log files
        char filename[50];
        snprintf(filename, sizeof(filename), "%s%d.dat", LOG_FILE_PREFIX, i);
        log_files[i] = fopen(filename, "a");
        if (log_files[i] == NULL) {
            fprintf(stderr, "Error opening log file %s\n", filename);
            gpioTerminate(); // Cleanup GPIO before exiting
            return 1;          // Exit if a log file cannot be opened.
        }
    }

    // Set up signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (!terminate) {
        for (int i = 0; i < NUM_SENSORS; ++i) {
            int sensor_value = read_sensor(SENSOR_PINS[i]);

            if (sensor_value >= 0) {
                float moisture_level = convert_to_moisture(sensor_value);
                control_relay(RELAY_PINS[i], moisture_level);
                log_data(i, sensor_value, moisture_level);
            } else {
                fprintf(stderr, "Error reading sensor %d: %d\n", i, sensor_value);
                // Log the error to the sensor's log file
                time_t rawtime;
                struct tm timeinfo;
                time(&rawtime);
                localtime_r(&rawtime, &timeinfo);
                char timestamp[20];
                strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &timeinfo);
                fprintf(log_files[i], "%s - ERROR: Sensor read failed with code %d\n", timestamp, sensor_value);
            }
        }
        gpioDelay(SAMPLING_DELAY_MS); // Delay between readings
    }

    // Cleanup and exit
    cleanup(0);
    return 0;
}

// Function to read sensor value
int read_sensor(int gpio_pin) {
    // Simulate reading an analog value from the sensor
    // In a real application, you would use an ADC to read the analog value
    // For this example, we'll use a simple digital read and return a value based on that.
    // A disconnected sensor should return a value that triggers the error condition.
    int sensor_value = gpioRead(gpio_pin);

    if (sensor_value == PI_TIMEOUT) {
        return -2; // Sensor disconnected or communication error
    } else if (sensor_value == PI_BAD_GPIO) {
        return -3; // Invalid GPIO pin
    } else if (sensor_value == PI_NOT_INITIALISED) {
        return -4; // pigpio not initialised
    } else {
        // Simulate an analog value based on the digital read
        // Assuming a simple scenario where HIGH means dry and LOW means wet
        return (sensor_value == 0) ? 700 : 300; // Simulate analog value (0-1023 range)
    }
}

// Function to convert sensor value to moisture percentage
float convert_to_moisture(int sensor_value) {
    // This is a placeholder conversion.  Real sensors require calibration.
    // Assuming sensor_value ranges from 0 (dry) to 1023 (wet).
    // Map the sensor value to a percentage.
    return 100.0f - ((float)sensor_value / 1023.0f) * 100.0f;
}

// Function to control the relay
void control_relay(int gpio_pin, float moisture_level) {
    if (moisture_level < MOISTURE_THRESHOLD) {
        gpioWrite(gpio_pin, 0); // Activate relay (LOW)
    } else {
        gpioWrite(gpio_pin, 1); // Deactivate relay (HIGH)
    }
}

// Function to log data to file
void log_data(int sensor_index, int sensor_value, float moisture_level) {
    time_t rawtime;
    struct tm timeinfo;
    time(&rawtime);
    localtime_r(&rawtime, &timeinfo);

    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &timeinfo);

    fprintf(log_files[sensor_index], "%s - Sensor Value: %d, Moisture Level: %.2f%%\n", timestamp, sensor_value, moisture_level);
    fflush(log_files[sensor_index]); // Ensure data is written to file immediately
}

// Function to cleanup GPIO and close files
void cleanup(int signum) {
    printf("Cleaning up and exiting...\n");

    // Close log files
    for (int i = 0; i < NUM_SENSORS; ++i) {
        if (log_files[i] != NULL) {
            fclose(log_files[i]);
        }
    }

    // Release GPIO pins and terminate pigpio
    for (int i = 0; i < NUM_SENSORS; ++i) {
        gpioSetMode(SENSOR_PINS[i], PI_INPUT); // Set back to input
        gpioWrite(RELAY_PINS[i], 1);           // Turn off relay
        gpioSetMode(RELAY_PINS[i], PI_INPUT);  // Set back to input
    }

    gpioTerminate();

    exit(0);
}

