    int reading = gpioRead(gpio_pin);
    if (reading < 0) {
        fprintf(stderr, "Error reading sensor value!\n");
        return -1; // Indicate an error
    }
    return reading;
}

// Function to control the relay
void control_relay(int gpio_pin, int state) {
    gpioWrite(gpio_pin, state);
}

// Function to log moisture reading to a file
void log_moisture_reading(int moisture_level) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    FILE *fp = fopen("soil_moisture.dat", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening file for logging!\n");
        return;
    }

    fprintf(fp, "%s, Moisture: %d\n", timestamp, moisture_level);
    fclose(fp);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as input and output
    gpioSetMode(SENSOR_PIN, PI_INPUT);
    gpioSetMode(RELAY_PIN, PI_OUTPUT);

    // Register signal handler for graceful termination
    signal(SIGINT, signal_handler);

    printf("Soil moisture monitoring started. Press Ctrl+C to exit.\n");

    // Main loop
    while (!terminate) {
        int moisture_level = read_soil_moisture(SENSOR_PIN);
        if (moisture_level < 0) {
            fprintf(stderr, "Error reading moisture level, skipping iteration.\n");
            sleep(5);
            continue;
        }

        printf("Moisture level: %d\n", moisture_level);

        if (moisture_level < MOISTURE_THRESHOLD) {
            printf("Moisture below threshold. Activating relay.\n");
            control_relay(RELAY_PIN, 1); // Activate relay
        } else {
            printf("Moisture level sufficient. Deactivating relay.\n");
            control_relay(RELAY_PIN, 0); // Deactivate relay
        }

        log_moisture_reading(moisture_level);

        sleep(5); // Wait 5 seconds
    }

    // Cleanup and terminate pigpio
    gpioTerminate();
    printf("Program terminated.\n");
    return 0;
}

