// Configuration file
#define CONFIG_FILE "file_logging.json"

// MQTT topic
#define MQTT_TOPIC "industrial/temperature_humidity"

// GPIO pin for DHT22 sensor
#define DHT_PIN 4

// Watchdog timer interval (seconds)
#define WATCHDOG_INTERVAL 30

// Global variables
static double temperature = 0.0;
static double humidity = 0.0;
static double temp_high_threshold = 30.0;
static double temp_low_threshold = 10.0;
static double humidity_high_threshold = 70.0;
static double humidity_low_threshold = 30.0;
static char *mqtt_broker_address = "localhost";
static int mqtt_broker_port = 1883;
static char *mqtt_client_id = "rpi_sensor_client";
static char *mqtt_username = NULL;
static char *mqtt_password = NULL;
static struct mosquitto *mosq = NULL;
static pthread_mutex_t sensor_data_mutex = PTHREAD_MUTEX_INITIALIZER;
static timer_t watchdog_timer;
static volatile sig_atomic_t running = 1;

// Function pointer types
typedef int (*SensorReadFunc)(double*, double*);
typedef int (*DataValidateFunc)(double, double);
typedef int (*ThresholdCompareFunc)(double, double, double);
typedef int (*DataLogFunc)(double, double);

// Function prototypes
int read_config_from_file(const char *filename);
int read_dht22_sensor(double *temperature, double *humidity);
int validate_temperature(double temperature);
int validate_humidity(double humidity);
int check_temp_high_threshold(double temperature, double threshold_high, double threshold_low);
int check_humidity_high_threshold(double humidity, double threshold_high, double threshold_low);
int log_sensor_data(double temperature, double humidity);
int mqtt_publish_data(double temperature, double humidity);
void *sensor_reading_thread(void *arg);
void *mqtt_publishing_thread(void *arg);
void watchdog_handler(int sig);
void setup_watchdog_timer();
void reset_watchdog_timer();
void signal_handler(int sig);
void reload_configuration(int sig);

// Function implementations

// Reload configuration
void reload_configuration(int sig) {
    if (sig == SIGHUP) {
        syslog(LOG_INFO, "Received SIGHUP. Reloading configuration...");
        if (read_config_from_file(CONFIG_FILE) != 0) {
            syslog(LOG_ERR, "Failed to reload configuration.");
        } else {
            syslog(LOG_INFO, "Configuration reloaded successfully.");
        }
    }
}

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    syslog(LOG_INFO, "Signal received, shutting down...");
    running = 0;

    // Cleanup resources
    pthread_mutex_destroy(&sensor_data_mutex);

    if (mosq) {
        mosquitto_disconnect(mosq);
        mosquitto_destroy(mosq);
        mosquitto_lib_cleanup();
    }

    closelog();
    exit(0);
}

// Watchdog timer handler
void watchdog_handler(int sig) {
    if (sig == SIGABRT) {
        syslog(LOG_ERR, "Watchdog timer expired. Restarting...");
        // Perform any necessary cleanup before restarting
        closelog();
        raise(SIGKILL); // Forcefully terminate the process to trigger a restart
    }
}

// Setup watchdog timer
void setup_watchdog_timer() {
    struct sigevent sev;
    struct itimerspec its;

    memset(&sev, 0, sizeof(sev));
    sev.sigev_notify = SIGEV_SIGNAL;
    sev.sigev_signo = SIGABRT;

    if (timer_create(CLOCK_REALTIME, &sev, &watchdog_timer) == -1) {
        syslog(LOG_ERR, "Failed to create watchdog timer: %s", strerror(errno));
        perror("timer_create");
        exit(EXIT_FAILURE);
    }

    its.it_value.tv_sec = WATCHDOG_INTERVAL;
    its.it_value.tv_nsec = 0;
    its.it_interval.tv_sec = WATCHDOG_INTERVAL;
    its.it_interval.tv_nsec = 0;

    if (timer_settime(watchdog_timer, 0, &its, NULL) == -1) {
        syslog(LOG_ERR, "Failed to set watchdog timer: %s", strerror(errno));
        perror("timer_settime");
        exit(EXIT_FAILURE);
    }

    syslog(LOG_INFO, "Watchdog timer started with interval %d seconds.", WATCHDOG_INTERVAL);
}

// Reset watchdog timer
void reset_watchdog_timer() {
    struct itimerspec its;

    its.it_value.tv_sec = WATCHDOG_INTERVAL;
    its.it_value.tv_nsec = 0;
    its.it_interval.tv_sec = WATCHDOG_INTERVAL;
    its.it_interval.tv_nsec = 0;

    if (timer_settime(watchdog_timer, 0, &its, NULL) == -1) {
        syslog(LOG_ERR, "Failed to reset watchdog timer: %s", strerror(errno));
        perror("timer_settime");
    }

    //syslog(LOG_DEBUG, "Watchdog timer reset.");
}

// Read configuration from JSON file
int read_config_from_file(const char *filename) {
    json_t *root;
    json_error_t error;

    root = json_load_file(filename, 0, &error);
    if (!root) {
        syslog(LOG_ERR, "Error loading JSON file: %s at line %d, column %d", error.text, error.line, error.column);
        return -1;
    }

    json_t *temp_high = json_object_get(root, "temp_high_threshold");
    json_t *temp_low = json_object_get(root, "temp_low_threshold");
    json_t *humidity_high = json_object_get(root, "humidity_high_threshold");
    json_t *humidity_low = json_object_get(root, "humidity_low_threshold");
    json_t *mqtt_broker = json_object_get(root, "mqtt_broker_address");
    json_t *mqtt_port = json_object_get(root, "mqtt_broker_port");
    json_t *mqtt_id = json_object_get(root, "mqtt_client_id");
    json_t *mqtt_user = json_object_get(root, "mqtt_username");
    json_t *mqtt_pass = json_object_get(root, "mqtt_password");

    if (temp_high && json_is_real(temp_high)) temp_high_threshold = json_real_value(temp_high);
    if (temp_low && json_is_real(temp_low)) temp_low_threshold = json_real_value(temp_low);
    if (humidity_high && json_is_real(humidity_high)) humidity_high_threshold = json_real_value(humidity_high);
    if (humidity_low && json_is_real(humidity_low)) humidity_low_threshold = json_real_value(humidity_low);
    if (mqtt_broker && json_is_string(mqtt_broker)) {
        free(mqtt_broker_address);
        mqtt_broker_address = strdup(json_string_value(mqtt_broker));
    }
    if (mqtt_port && json_is_integer(mqtt_port)) mqtt_broker_port = json_integer_value(mqtt_port);
    if (mqtt_id && json_is_string(mqtt_id)) {
        free(mqtt_client_id);
        mqtt_client_id = strdup(json_string_value(mqtt_id));
    }
    if (mqtt_user && json_is_string(mqtt_user)) {
        free(mqtt_username);
        mqtt_username = strdup(json_string_value(mqtt_user));
    }
    if (mqtt_pass && json_is_string(mqtt_pass)) {
        free(mqtt_password);
        mqtt_password = strdup(json_string_value(mqtt_pass));
    }

    json_decref(root);
    syslog(LOG_INFO, "Configuration loaded successfully.");
    return 0;
}

// Read DHT22 sensor data
int read_dht22_sensor(double *temperature, double *humidity) {
    int data[5] = {0, 0, 0, 0, 0};
    int laststate = HIGH;
    int j = 0;

    // Reset data array
    data[0] = data[1] = data[2] = data[3] = data[4] = 0;

    // Request data
    pinMode(DHT_PIN, OUTPUT);
    digitalWrite(DHT_PIN, LOW);
    delay(18);
    digitalWrite(DHT_PIN, HIGH);
    delayMicroseconds(40);
    pinMode(DHT_PIN, INPUT);

    // Get data
    unsigned int loops = 100000;
    for (int i = 0; i < loops; i++) {
        int currentState = digitalRead(DHT_PIN);
        if (currentState != laststate) {
            unsigned int counter = 0;
            while (digitalRead(DHT_PIN) == currentState) {
                counter++;
                delayMicroseconds(1); // Reduced delay for faster loop
                if (counter == 255) {
                    break;
                }
            }

            if (counter >= 255) {
                break;
            }

            if ((i > 4) && (i < 45)) {
                data[j / 8] <<= 1;
                if (counter > 16) {
                    data[j / 8] |= 1;
                }
                j++;
            }
        }
        laststate = currentState;
    }

    // Check we read 40 bits (8bit x 5 )
    if (j < 40) {
        syslog(LOG_ERR, "DHT22: Not enough data received, only %d bits", j);
        return -1;
    }

    // Verify checksum
    if (data[4] != ((data[0] + data[1] + data[2] + data[3]) & 0xFF)) {
        syslog(LOG_ERR, "DHT22: Checksum failure: %d != %d", data[4], ((data[0] + data[1] + data[2] + data[3]) & 0xFF));
        return -1;
    }

    // Get temperature and humidity
    *humidity = (double)((data[0] << 8) + data[1]) / 10.0;
