int read_dht22(float *temperature, float *humidity) {
    int data[5] = {0, 0, 0, 0, 0};
    int laststate = HIGH;
    int j = 0;

    // Set pin to output
    pinMode(DHT22_PIN, OUTPUT);
    digitalWrite(DHT22_PIN, LOW);
    delay(1);
    digitalWrite(DHT22_PIN, HIGH);
    delayMicroseconds(30);
    pinMode(DHT22_PIN, INPUT);

    // Read data
    for (int i = 0; i < 85; i++) {
        int counter = 0;
        while (digitalRead(DHT22_PIN) == laststate) {
            counter++;
            delayMicroseconds(1);
            if (counter == 255) {
                return -1; // Timeout
            }
        }
        laststate = digitalRead(DHT22_PIN);

        if (counter > 3) {
            data[j / 8] <<= 1;
            if (counter > 16)
                data[j / 8] |= 1;
            j++;
        }
    }

    if (j < 40) {
        return -1; // Not enough data
    }

    // Check checksum
    if (data[4] != ((data[0] + data[1] + data[2] + data[3]) & 0xFF)) {
        return -1; // Checksum error
    }

    *humidity = (float)data[0] * 256 + data[1];
    *humidity /= 10;

    *temperature = (float)(data[2] & 0x7F) * 256 + data[3];
    *temperature /= 10;
    if (data[2] & 0x80) {
        *temperature *= -1;
    }

    return 0; // Success
}

