    }

    json_t *temp_max = json_object_get(root, "temperature_max");
    json_t *temp_min = json_object_get(root, "temperature_min");
    json_t *humidity_max = json_object_get(root, "humidity_max");
    json_t *humidity_min = json_object_get(root, "humidity_min");

    if (!json_is_real(temp_max) || !json_is_real(temp_min) ||
        !json_is_real(humidity_max) || !json_is_real(humidity_min)) {
        fprintf(stderr, "Error: Invalid threshold values in %s. Check the file.\n", LOG_FILE);
        json_decref(root);
        return -1; // Invalid data types
    }

    thresholds->temperature_max = json_real_value(temp_max);
    thresholds->temperature_min = json_real_value(temp_min);
    thresholds->humidity_max = json_real_value(humidity_max);
    thresholds->humidity_min = json_real_value(humidity_min);

    json_decref(root);
    return 0; // Success
}

