        return -1; // File open error
    }

    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char s[64];
    strftime(s, sizeof(s), "%Y-%m-%d %H:%M:%S", tm);

    fprintf(fp, "%s, Temperature: %.2f°C, Humidity: %.2f%%\n", s, temperature, humidity);
    fclose(fp);
    return 0; // Success
}

