    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: Could not initialize wiringPi.\n");
        return 1;
    }

    // Read thresholds from file
    if (read_thresholds(&thresholds) != 0) {
        fprintf(stderr, "Warning: Using default thresholds.\n");
    }

