        // Read sensor data
        if (read_dht22(&temperature, &humidity) == 0) {
            // Check if thresholds are exceeded
            if (temperature > thresholds.temperature_max || temperature < thresholds.temperature_min ||
                humidity > thresholds.humidity_max || humidity < thresholds.humidity_min) {
