#define STEP_DELAY 500000  // Step delay in microseconds (500 us per step)
#define MOTOR_A_STEP_PIN 18
#define MOTOR_A_DIR_PIN 17
#define MOTOR_B_STEP_PIN 27
#define MOTOR_B_DIR_PIN 22
#define NUM_ITERATIONS 5  // Number of iterations for the Hilbert curve

void setup() {
    wiringPiSetup();

    pinMode(MOTOR_A_STEP_PIN, OUTPUT);
    pinMode(MOTOR_A_DIR_PIN, OUTPUT);
    pinMode(MOTOR_B_STEP_PIN, OUTPUT);
    pinMode(MOTOR_B_DIR_PIN, OUTPUT);

    printf("Initializing motors...\n");
    delay(2000);
}

void motor_a_step(int steps) {
    digitalWrite(MOTOR_A_DIR_PIN, HIGH);
    for (int i = 0; i < steps; i++) {
        digitalWrite(MOTOR_A_STEP_PIN, HIGH);
        usleep(STEP_DELAY);
        digitalWrite(MOTOR_A_STEP_PIN, LOW);
        usleep(STEP_DELAY);
    }
}

void motor_b_step(int steps) {
    digitalWrite(MOTOR_B_DIR_PIN, HIGH);
    for (int i = 0; i < steps; i++) {
        digitalWrite(MOTOR_B_STEP_PIN, HIGH);
        usleep(STEP_DELAY);
        digitalWrite(MOTOR_B_STEP_PIN, LOW);
        usleep(STEP_DELAY);
    }
}

void hilbert_curve(int iterations) {
    int steps = pow(4, iterations);
    int x = 0;
    int y = steps - 1;
    int sequence[steps * 2];

    for (int i = 0; i < steps * 2; i++) {
        sequence[i] = -1;
    }

    sequence[0] = 0;
    sequence[1] = 1;

    for (int bit = 2; bit < steps * 2; bit++) {
        int current = sequence[bit - 1];
        int next = current;

        if (bit % 2 == 0) {
            next += steps;
            if (current < steps - 1) {
                if ((current & 1) != (next & 1)) {
                    next++;
                }
            }
        } else {
            if (current > 0) {
                if ((current - 1) & (next & 1)) {
                    next -= steps;
                }
            }
        }

        sequence[bit] = next;
    }

    motor_a_step(sequence[0]);
    motor_b_step(sequence[1]);

    for (int i = 2; i < steps * 2; i += 2) {
        motor_a_step(sequence[i] - sequence[i - 2]);
        motor_b_step(sequence[i - 1] - sequence[i - 3]);
    }
}

int main(void) {
    setup();

    try {
        hilbert_curve(NUM_ITERATIONS);
    } catch (...) {
        printf("Error during curve generation or execution.\n");
        return 1;
    }

    printf("Finished drawing the Hilbert curve.\n");

