    int temp_msb = wiringPiI2CReadReg16(fd, 0); // Read temperature MSB and LSB
    if (temp_msb == -1) {
        perror("Error reading temperature MSB");
        return -1;
    }
    int hum_msb = wiringPiI2CReadReg16(fd, 2); // Read humidity MSB and LSB
    if (hum_msb == -1) {
