#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <wiringPi.h>
#include <syslog.h>

#define RELAY_PIN 17
#define TOUCH_SENSOR_PIN 4
#define DEBOUNCE_DELAY 50 // Debounce delay in milliseconds
#define LOG_FACILITY LOCAL0

void log_message(const char *message) {
    openlog("relay_control", LOG_PID | LOG_CONS | LOG_NDELAY, LOG_FACILITY);
    syslog(LOG_INFO, "%s", message);
    closelog();
}

void init_wiringPi() {
    if (wiringPiSetup() == -1) {
        log_message("Failed to initialize wiringPi");
        exit(1);
    }

    pinMode(RELAY_PIN, OUTPUT);
    pinMode(TOUCH_SENSOR_PIN, INPUT);
}

int read_touch_sensor() {
    int value = digitalRead(TOUCH_SENSOR_PIN);
    usleep(10000); // Debounce by delaying the next read
    return digitalRead(TOUCH_SENSOR_PIN) == value;
}

void toggle_relay() {
    digitalWrite(RELAY_PIN, !digitalRead(RELAY_PIN));
    log_message("Relay state changed to: " + (digitalRead(RELAY_PIN) ? "ON" : "OFF"));
}

