/**
 * @brief Reads acceleration data from the Omron D7S sensor.
 *
 * @param fd I2C file descriptor.
 * @param x Pointer to store X acceleration.
 * @param y Pointer to store Y acceleration.
 * @param z Pointer to store Z acceleration.
 * @return 0 on success, -1 on error.
 */
int read_acceleration_data(int fd, float *x, float *y, float *z) {
    int16_t raw_x, raw_y, raw_z;
    int x_lsb, x_msb, y_lsb, y_msb, z_lsb, z_msb;

    x_lsb = wiringPiI2CReadReg8(fd, D7S_REG_X_LSB);
    if (x_lsb < 0) {
        fprintf(stderr, "Error reading X LSB from I2C.\n");
        return -1;
    }
    x_msb = wiringPiI2CReadReg8(fd, D7S_REG_X_MSB);
    if (x_msb < 0) {
        fprintf(stderr, "Error reading X MSB from I2C.\n");
        return -1;
    }

    y_lsb = wiringPiI2CReadReg8(fd, D7S_REG_Y_LSB);
    if (y_lsb < 0) {
        fprintf(stderr, "Error reading Y LSB from I2C.\n");
        return -1;
    }
    y_msb = wiringPiI2CReadReg8(fd, D7S_REG_Y_MSB);
    if (y_msb < 0) {
        fprintf(stderr, "Error reading Y MSB from I2C.\n");
        return -1;
    }

    z_lsb = wiringPiI2CReadReg8(fd, D7S_REG_Z_LSB);
    if (z_lsb < 0) {
        fprintf(stderr, "Error reading Z LSB from I2C.\n");
        return -1;
    }
    z_msb = wiringPiI2CReadReg8(fd, D7S_REG_Z_MSB);
    if (z_msb < 0) {
        fprintf(stderr, "Error reading Z MSB from I2C.\n");
        return -1;
    }

    raw_x = (int16_t)((x_msb << 8) | x_lsb);
    raw_y = (int16_t)((y_msb << 8) | y_lsb);
    raw_z = (int16_t)((z_msb << 8) | z_lsb);

    // Convert raw values to g (assuming a sensitivity of 0.004g/LSB)
    *x = (float)raw_x * 0.004;
    *y = (float)raw_y * 0.004;
    *z = (float)raw_z * 0.004;

    return 0;
}

/**
 * @brief Checks if the acceleration magnitude exceeds the threshold.
 *
 * @param x X acceleration.
 * @param y Y acceleration.
 * @param z Z acceleration.
 * @param threshold Vibration threshold in g.
 * @return 1 if the threshold is exceeded, 0 otherwise.
 */
int check_threshold(float x, float y, float z, float threshold) {
    float magnitude = sqrtf(x * x + y * y + z * z);
    return (magnitude > threshold) ? 1 : 0;
}

/**
