#define DEBOUNCE_TIME 500

// Global variables
volatile unsigned long lastDetectionTime = 0;
volatile sig_atomic_t programRunning = 1;

// Function prototypes
void motionDetected(void);
void beep(int duration_ms);
void logMotion(void);
void signalHandler(int signum);

// Interrupt handler function
void motionDetected(void) {
    unsigned long currentTime = millis();

    // Debounce the interrupt
    if (currentTime - lastDetectionTime > DEBOUNCE_TIME) {
        printf("Motion detected!\n");
        beep(500);
        logMotion();
        lastDetectionTime = currentTime;
    }
}

// Function to activate the buzzer for a specified duration
void beep(int duration_ms) {
    digitalWrite(BUZZER_PIN, HIGH); // Activate buzzer
    delay(duration_ms);
    digitalWrite(BUZZER_PIN, LOW);  // Deactivate buzzer
}

