    long start_time = time_time();
    while (time_time() - start_time < duration) {
        gpioWrite(LED_PIN, 1); // Turn LED on
        gpioDelay(on_time * 1000000); // Delay in microseconds
        gpioWrite(LED_PIN, 0); // Turn LED off
        gpioDelay(off_time * 1000000); // Delay in microseconds
    }
}

