#include <arpa/inet.h>

// Configuration
#define PIR_PIN 17      // WiringPi pin number for PIR sensor
#define LED_PIN 18      // WiringPi pin number for LED
#define SERVER_IP "127.0.0.1" // Server IP address (loopback for testing)
#define SERVER_PORT 5000    // Server port number

// Global variables (volatile for signal handling)
volatile sig_atomic_t program_running = 1;

// Function prototypes
