#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <time.h>
#include <string.h>
#include <wiringPi.h>

#define LOCK_PIN1 17
#define LOCK_PIN2 27
#define LOCK_DELAY 3
#define LOG_FILE "/var/log/lock_events.log"

void log_event(const char *event) {
    time_t rawtime;
    struct tm *timeinfo;
    char time_string[80];
    char log_line[120];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(time_string, sizeof(time_string), "%Y-%m-%d %H:%M:%S", timeinfo);
    snprintf(log_line, sizeof(log_line), "%s: %s\n", time_string, event);

    FILE *log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        return;
    }

    fputs(log_line, log_file);
    fclose(log_file);
}

void unlock_lock(int gpio_pin) {
    printf("Unlocking lock on GPIO %d...\n", gpio_pin);
    log_event(("Unlock" ": GPIO " + to_string(gpio_pin)).c_str());

    wiringPiSetup();
    pinMode(gpio_pin, OUTPUT);
    digitalWrite(gpio_pin, HIGH);
    delay(LOCK_DELAY * 1000);
    digitalWrite(gpio_pin, LOW);
    delay(LOCK_DELAY * 1000);
}

void lock_lock(int gpio_pin) {
    printf("Locking lock on GPIO %d...\n", gpio_pin);
    log_event(("Lock" ": GPIO " + to_string(gpio_pin)).c_str());

    wiringPiSetup();
    pinMode(gpio_pin, OUTPUT);
    digitalWrite(gpio_pin, LOW);
}

int main() {
    wiringPiSetup();

    if (wiringPiSetupGpio() < 0) {
        perror("Failed to initialize wiringPi");
        return 1;
    }

    pinMode(LOCK_PIN1, INPUT);
    pinMode(LOCK_PIN2, INPUT);

    printf("Initializing locks...\n");
    lock_lock(LOCK_PIN1);
    lock_lock(LOCK_PIN2);

    int access_code[] = {1, 2, 3, 4, 5}; // Replace this with your custom access code
    int num_digits = sizeof(access_code) / sizeof(int);
    int entered_code[num_digits];
    int index = 0;

    while (1) {
        // Check if any lock is open
        if (digitalRead(LOCK_PIN1) == HIGH || digitalRead(LOCK_PIN2) == HIGH) {
            log_event("Access denied - lock already open");
            continue;
        }

        // Get user input for the access code
        printf("Enter the access code:\n");
        for (int i = 0; i < num_digits; ++i) {
            scanf("%d", &entered_code[i]);
            if (entered_code[i] != access_code[i]) {
                log_event("Access denied - incorrect code");
                break;
            }
            if (i == num_digits - 1) {
                // All digits are correct, unlock the locks
