#define PIR_GPIO 4
#define RELAY1_GPIO 17
#define RELAY2_GPIO 27
#define DEBOUNCE_TIME 200  // milliseconds
#define LIGHT_ON_TIME 5     // seconds
#define LOG_FILE "/var/log/lighting.log"

static volatile int running = 1;
static volatile unsigned long last_trigger_time = 0;
FILE *log_file = NULL;

void cleanup(int signal);
void pir_callback(int gpio, int level, unsigned int tick, void *userdata);

void log_event(const char *message) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp) - 1, "%Y-%m-%d %H:%M:%S", t);

    if (log_file != NULL) {
        fprintf(log_file, "%s: %s\n", timestamp, message);
        fflush(log_file);
    } else {
        fprintf(stderr, "Error: Log file not opened.\n");
    }
}

void pir_callback(int gpio, int level, unsigned int tick, void *userdata) {
    unsigned long now = gpioTick();
    if (now - last_trigger_time > DEBOUNCE_TIME * 1000) {
        last_trigger_time = now;

        log_event("Motion detected!");

        gpioWrite(RELAY1_GPIO, 1); // Turn on relay 1
        gpioWrite(RELAY2_GPIO, 1); // Turn on relay 2
        sleep(LIGHT_ON_TIME); // Wait for specified duration
        gpioWrite(RELAY1_GPIO, 0); // Turn off relay 1
        gpioWrite(RELAY2_GPIO, 0); // Turn off relay 2

        log_event("Lights turned off.");
    }
}

void cleanup(int signal) {
    printf("Cleaning up and exiting...\n");
    running = 0;

    // Turn off relays
    gpioWrite(RELAY1_GPIO, 0);
    gpioWrite(RELAY2_GPIO, 0);

    // Close log file
    if (log_file != NULL) {
        fclose(log_file);
    }

    gpioTerminate();
    exit(0);
}

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure GPIO pins
    gpioSetMode(PIR_GPIO, PI_INPUT);
    gpioSetMode(RELAY1_GPIO, PI_OUTPUT);
    gpioSetMode(RELAY2_GPIO, PI_OUTPUT);

    // Initialize relays to OFF state
    gpioWrite(RELAY1_GPIO, 0);
    gpioWrite(RELAY2_GPIO, 0);

    // Open log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", LOG_FILE);
        gpioTerminate();
        return 1;
    }

    // Set up signal handlers
    signal(SIGINT, cleanup);
    signal(SIGTERM, cleanup);

