```bash
sudo apt-get update
sudo apt-get install wiringPi
```

Now, create a new file called `smart_lighting.c` and paste the following code:

```c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/time.h>
#include <wiringPi.h>
#include <fcntl.h>
#include <sys/stat.h>

#define RELAY_PIN1 17
#define RELAY_PIN2 27
#define PIR_PIN 4
#define LOG_FILE "/var/log/lighting.log"

void log_event(const char *message) {
    time_t rawtime;
    struct tm *timeinfo;
    char time_string[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(time_string, sizeof(time_string), "%Y-%m-%d %H:%M:%S", timeinfo);
    fprintf(stderr, "%s: %s\n", time_string, message);
    FILE *log_file = fopen(LOG_FILE, "a");
    fprintf(log_file, "%s: %s\n", time_string, message);
    fclose(log_file);
}

void debounce(int pin, int duration) {
    int state = digitalRead(pin);
    int previous_state = state;
    struct timeval start, end;

    gettimeofday(&start, NULL);

    while (duration > 0) {
        usleep(100000);
        state = digitalRead(pin);

        if (state != previous_state) {
            gettimeofday(&end, NULL);
            if (duration_between(&start, &end) > 20) {
                break;
            } else {
                duration += 20;
            }
        }

        previous_state = state;
    }
}

int main(void) {
    wiringPiSetup();

    pinMode(PIR_PIN, INPUT);
    pinMode(RELAY_PIN1, OUTPUT);
