```c
#include <stdio.h>
#include <unistd.h>
#include <pigpio.h>

#define LED_PIN 22

int main() {
    // Initialize the pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Failed to initialize pigpio library\n");
        return 1;
    }

    // Set the LED pin as output
    gpioSetMode(LED_PIN, PI_OUTPUT);

    // Main loop to blink the LED
    for (int i = 0; i < 10; i++) {
        // Turn on the LED
        gpioWrite(LED_PIN, 1);
        usleep(500000); // 500 ms delay

        // Turn off the LED
        gpioWrite(LED_PIN, 0);
        usleep(500000); // 500 ms delay
    }

    // Terminate the pigpio library
    gpioTerminate();

    return 0;
}
```

4. Save the file and exit the text editor.

5. Compile the C program using gcc:

```bash
gcc blink.c -o blink -lwiringPi -lpigpio -Wall
```

6. Run the compiled program:

```bash
sudo ./blink
```

