To create a C program for Raspberry Pi using Pigpio library to initialize an SSD1306 OLED display and display the text 'Hello, OLED!', follow the steps below:

1. Install the Pigpio library on your Raspberry Pi:

```bash
sudo apt-get update
sudo apt-get install pigpio
```

2. Create a new C file named `oled_hello.c` and paste the following code:

```c
#include <stdio.h>
#include <unistd.h>
#include <string.h>
#include <stdint.h>
#include <pigpio.h>

#define SDA_PIN 20
#define SCL_PIN 21
#define OLED_RESET 18
#define I2C_ADDR 0x3C

void i2c_write(uint8_t reg, uint8_t data) {
    uint8_t buffer[2];
    buffer[0] = reg;
    buffer[1] = data;
    if (igpiod_write(igpiod_claim(0, SDA_PIN, GPIOD_INOUT) < 0 ||
                     igpiod_write(igpiod_claim(0, SCL_PIN, GPIOD_INOUT) < 0) ||
                     i2c_master_write_read(i2c_setup(I2C_BUS, I2C_SPEED_STANDARD), I2C_ADDR, buffer, 2, NULL, 0) < 2) {
        perror("i2c_write error");
    }
    igpiod_release(igpiod_claim(0, SDA_PIN, GPIOD_IN));
    igpiod_release(igpiod_claim(0, SCL_PIN, GPIOD_IN));
}

void oled_init() {
    gpioTerm(OLED_RESET);
    gpioSetMode(OLED_RESET, PI_OUTPUT);
    gpioWrite(OLED_RESET, 1);
    sleep(1);
    gpioWrite(OLED_RESET, 0);
    sleep(10);
    gpioWrite(OLED_RESET, 1);

    i2c_write(0x21, 0x0F); // Set Column Address
    i2c_write(0x20, 0x00); // Set Page Address
    i2c_write(0x8D, 0x14); // Set COM Output Scan Direction
    i2c_write(0xA8, 0x3F); // Set COM Pins Hardware Configuration
    i2c_write(0xD3, 0x00); // Set Display Offset
    i2c_write(0xD5, 0x80); // Set Display Clock Divide Ratio
    i2c_write(0xD9, 0xF1); // Set Pre-Charge Period
    i2c_write(0xDB, 0x20); // Set VCOM Deselect Level
    i2c_write(0xA4, 0xA1); // Set Normal Display
    i2c_write(0xA6, 0xA1); // Set Multiplex Ratio
    i2c_write(0xAF, 0x00); // Display On
}

void oled_puts(char *str) {
    uint8_t len = strlen(str);
    for (int i = 0; i < len; i++) {
        i2c_write(0x40 + (i / 16), str[i]);
        if ((i + 1) % 16 == 0) {
            i2c_write(0x40 + (i / 16), 0xB0 | (i / 16));
        }
    }
}

int main() {
    if (gpioInitialise() < 0) {
        perror("gpioInitialise error");
        return 1;
    }

    if (gpioSetMode(SDA_PIN, PI_OUTPUT) < 0 ||
        gpioSetMode(SCL_PIN, PI_OUTPUT) < 0 ||
        gpioSetMode(OLED_RESET, PI_OUTPUT) < 0) {
        perror("gpioSetMode error");
        return 1;
    }

    oled_init();
    char message[] = "Hello, OLED!";
    oled_puts(message);

    gpioTerm();
    return 0;
}
```

3. Compile the C code with the following command:

```bash
gcc -o oled_hello oled_hello.c -lwiringPi -lpthread -lrt -lrt
```

4. Run the compiled program:

```bash
./oled_hello
```

