void log_lux(float lux, const char *filename) {
    char timestamp[20];
    time_t rawtime;
    struct tm *timeinfo;

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    FILE *file = fopen(filename, "a");
    if (file == NULL) {
        perror("Failed to open log file");
        return;
    }

    fprintf(file, "%s: Lux = %.2f\n", timestamp, lux);
    fclose(file);
}

int read_lux() {
    unsigned char buf[2];
    int i2c_status = 0;

    i2c_status = i2c_readByteData(gpioTerm, BH1750_ADDR, 0x23, &buf[0]);
    if (i2c_status < 0) {
        perror("Error reading from I2C");
        return -1;
    }

    i2c_status = i2c_readByteData(gpioTerm, BH1750_ADDR, 0x24, &buf[1]);
    if (i2c_status < 0) {
        perror("Error reading from I2C");
        return -1;
    }

    float lux = (buf[0] << 8 | buf[1]) * 1.225;
    return (int)lux;
}

