    if (i2c_status < 0) {
        perror("Error initializing I2C");
        return 1;
    }

    while (1) {
        current_lux = read_lux();
        if (current_lux < 0) {
            perror("Error reading lux value");
            break;
        }

        if (abs(current_lux - last_lux) >= 5) {
            last_lux = current_lux;
            log_lux(last_lux, "light_log.txt");
