    waitpid(-1, &status, 0);

    // Send TERM signal to the main process
    kill(pid, SIGTERM);

    // Wait for the main process to finish
    waitpid(pid, &status, 0);

    // If the main process doesn't exit cleanly, send KILL signal
    if (WIFEXITED(status)) {
