#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <pigpio.h>

#define I2C_ADDR_HMC5883L 0x1E
#define X_OFFSET 140
#define Y_OFFSET 130
#define Z_OFFSET 145
#define LED_GPIO 18

int i2c_init(int *file) {
    char filename[] = "/dev/i2c-1";
    if ((*file = open(filename, O_RDWR)) < 0) {
        perror("Failed to open I2C bus");
        return -1;
    }

    if (ioctl(*file, I2C_SLAVE, I2C_ADDR_HMC5883L) < 0) {
        perror("Failed to acquire I2C address");
        close(*file);
        return -1;
    }

    return 0;
}

void i2c_read(int file, unsigned char reg, unsigned char *buf, int len) {
    if (i2c_master_writeRead(file, &reg, 1, buf, len) != len) {
        perror("Failed to read from HMC5883L");
    }
}

float get_heading(unsigned char *data) {
    float x = (data[0] * 256 + data[1]) / 16384.0 * (X_OFFSET - 128) + 128;
