#define GPIO_PIN 17
#define BUFFER_SIZE 10

// Structure to represent an interlock event
typedef struct {
    time_t timestamp;
    int state;
} Event;

// Circular buffer
Event *circularBuffer;
int head = 0;
int tail = 0;
int count = 0;

// Global variable for tilt switch state (volatile for interrupt handling)
volatile int tiltSwitchState = 0;

// Function prototypes
void enqueueEvent(Event event);
Event dequeueEvent(void);
void logEvent(int state);
void displayLast10Events(void);
void sendEventToServer(Event event);
void tiltSwitchInterruptHandler(void);
void timerHandler(void);
void signalHandler(int signal);

// Enqueue an event into the circular buffer
void enqueueEvent(Event event) {
    circularBuffer[head] = event;
    head = (head + 1) % BUFFER_SIZE;
    if (count == BUFFER_SIZE) {
        tail = (tail + 1) % BUFFER_SIZE;
    } else {
        count++;
    }
}

// Dequeue an event from the circular buffer (not used but included for completeness)
Event dequeueEvent(void) {
    Event event = circularBuffer[tail];
    tail = (tail + 1) % BUFFER_SIZE;
    if (count > 0) {
        count--;
    }
    return event;
}

// Log an event (create and enqueue)
void logEvent(int state) {
    Event event;
    event.timestamp = time(NULL);
    event.state = state;
    enqueueEvent(event);
    sendEventToServer(event);
}

// Display the last 10 events via UART
void displayLast10Events(void) {
    printf("\n--- Last 10 Interlock Events ---\n");
    int i;
    int index = tail;
    for (i = 0; i < count; i++) {
        printf("Timestamp: %ld, State: %d\n", circularBuffer[index].timestamp, circularBuffer[index].state);
        index = (index + 1) % BUFFER_SIZE;
    }
    printf("--------------------------------\n");
}

// Simulate sending an event to a central server
void sendEventToServer(Event event) {
    printf("Sending event to server: { \"timestamp\": %ld, \"state\": %d }\n", event.timestamp, event.state);
}

// Interrupt handler for the tilt switch
void tiltSwitchInterruptHandler(void) {
    tiltSwitchState = digitalRead(GPIO_PIN);
