```c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <time.h>
#include <string.h>
#include <pigpio.h>

#define LOCK1_GPIO 17
#define LOCK2_GPIO 27
#define BUTTON_GPIO 4
#define LOG_FILE "lock_events.log"

typedef enum {
    UNLOCK_1 = 0,
    UNLOCK_2 = 1,
    LOCK_1 = 2,
    LOCK_2 = 3,
    BUTTON_PRESSED = 4,
    BUTTON_RELEASED = 5
} LockEvent;

void log_event(LockEvent event, int lock_id) {
    time_t rawtime;
    struct tm * timeinfo;
    char time_string[80];
    FILE * log_file = fopen(LOG_FILE, "a");

    if (log_file == NULL) {
        perror("Error opening log file");
        return;
    }

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(time_string, sizeof(time_string), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s, %d, %d\n", time_string, event, lock_id);
    fclose(log_file);
}

int init_gpio() {
    if (gpioInitialise() < 0) {
        perror("Failed to initialize pigpio library");
        return -1;
    }

    if (gpioSetMode(BUTTON_GPIO, PI_INPUT) < 0) {
        perror("Failed to set button GPIO mode");
        return -1;
    }

    if (gpioSetMode(LOCK1_GPIO, PI_OUTPUT) < 0) {
        perror("Failed to set lock 1 GPIO mode");
        return -1;
    }

    if (gpioSetMode(LOCK2_GPIO, PI_OUTPUT) < 0) {
        perror("Failed to set lock 2 GPIO mode");
        return -1;
    }

    return 0;
}

int debounce_button(int delay_ms) {
    int previous_state = gpioRead(BUTTON_GPIO);
    int current_state;
    int debounce_count = 0;

    while (debounce_count < 50) {
        usleep(delay_ms);
        current_state = gpioRead(BUTTON_GPIO);

        if (previous_state != current_state) {
            debounce_count = 0;
        } else {
            debounce_count++;
        }

        previous_state = current_state;
    }

    return current_state;
}

void control_lock(int lock_id, int action) {
    if (action == UNLOCK_1 || action == LOCK_1) {
        gpioWrite(LOCK1_GPIO, action == UNLOCK_1 ? PI_LOW : PI_HIGH);
    }

    if (action == UNLOCK_2 || action == LOCK_2) {
        gpioWrite(LOCK2_GPIO, action == UNLOCK_2 ? PI_LOW : PI_HIGH);
    }
}

int main() {
    int gpio_init_result = init_gpio();

    if (gpio_init_result < 0) {
        return 1;
    }

    int button_state = debounce_button(50);
    int prev_button_state = button_state;

    while (1) {
        int current_button_state = debounce_button(50);

        if (current_button_state != prev_button_state) {
            if (current_button_state == PI_HIGH) {
                log_event(BUTTON_PRESSED, -1);
            } else {
                int lock_id = (prev_button_state == PI_HIGH) ? 1 : 2;
                log_event(BUTTON_RELEASED, lock_id);

                if (lock_id == 1) {
                    control_lock(lock_id, (prev_button_state == PI_HIGH) ? UNLOCK_1 : LOCK_1);
                } else {
                    control_lock(lock_id, (prev_button_state == PI_HIGH) ? UNLOCK_2 : LOCK_2);
                }
            }
            prev_button_state = current_button_state;
        }
    }

    gpioTerm();
    return 0;
}
