        return 0; // Or some error value
    }

    int handle = i2c_handles[sensor_index];
    int touch_status = i2c_read_data(handle, 0x00); // Read electrode touch status

    if (touch_status < 0) {
        char error_message[50];
        snprintf(error_message, sizeof(error_message), "Error reading touch data from sensor %d", sensor_index);
        log_error(error_message);
        return 0; // Or some error value
    }

    // Validate touch data (example: check if any electrode is touched)
    if (touch_status > 0) {
        return touch_status; // Return the raw touch status
    } else {
        return 0; // No touch detected
    }
}

// Function to fade an LED using PWM
void fade_led(int gpio) {
    int duty_cycle = 0;
    int direction = 1; // 1 for increasing, -1 for decreasing

    while (!terminate) {
        gpioPWM(gpio, duty_cycle);
        duty_cycle += FADE_STEP * direction;

        if (duty_cycle >= 255) {
            duty_cycle = 255;
            direction = -1;
        } else if (duty_cycle <= 0) {
            duty_cycle = 0;
            direction = 1;
        }

        gpioDelay(FADE_DELAY * 1000); // Convert milliseconds to microseconds
    }
