#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <wiringPi.h>

#define DATA_PIN 18
#define CLOCK_PIN 23
#define LATCH_PIN 24

void sevenSegmentWrite(unsigned char data) {
    digitalWrite(LATCH_PIN, LOW);
    shiftOut(DATA_PIN, CLOCK_PIN, MSBFIRST, data);
    digitalWrite(LATCH_PIN, HIGH);
}

void displayRandomNumber() {
    unsigned char numbers[] = {0b01111110, 0b00000110, 0b10110000, 0b10111111, 0b01100110, 0b01101101, 0b01111001, 0b00110000, 0b01110000, 0b01100000};
    unsigned char tens = rand() % 10;
    unsigned char units = rand() % 10;
    sevenSegmentWrite(numbers[tens * 10 + units]);
}

