    wiringPiSetupGpio();
    pinMode(DATA_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);
    pinMode(LATCH_PIN, OUTPUT);

    while (1) {
        displayRandomNumber();
        usleep(2000000); // wait for 2 seconds
    }

    return 0;
}
