    int adc = 0;
    for (int i = 0; i < 100; i++) {
        digitalWrite(PWM_CHANNEL, LOW);
        usleep(2);
        digitalWrite(PWM_CHANNEL, HIGH);
        usleep(2);
        digitalWrite(PWM_CHANNEL, LOW);
        adc += pulseIn(ADC_CHANNEL, HIGH);
    }
    adc /= 100;
    return adc;
}

