To create a C program for Raspberry Pi 5 using the pigpio library to monitor an MQ-135 air quality sensor and activate a 12V ventilation fan based on CO2 threshold, you can follow the steps below. This example assumes you have already installed the pigpio library and connected the MQ-135 sensor to GPIO 4 and the relay to GPIO 17.

1. First, make sure you have the pigpio library installed on your Raspberry Pi:

```bash
sudo apt-get install pigpio
```

2. Create a new file called `air_quality_monitor.c` and paste the following code:

```c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <time.h>
#include <pigpio.h>

#define SENSOR_PIN 4
#define RELAY_PIN 17
#define CO2_THRESHOLD 200
#define LOG_FILE "air_quality.log"

void log_message(const char *message) {
    FILE *log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t current_time = time(NULL);
    char time_string[20];
    strftime(time_string, sizeof(time_string), "%Y-%m-%d %H:%M:%S", localtime(&current_time));
    fprintf(log_file, "%s: %s\n", time_string, message);
    fclose(log_file);
}

int init_pigpio() {
    if (gpioInitialise() < 0) {
        perror("Error initializing pigpio");
        return -1;
    }

    gpioSetMode(SENSOR_PIN, PI_INPUT);
    gpioSetMode(RELAY_PIN, PI_OUTPUT);
    gpioSetPullUp(SENSOR_PIN);

    return 0;
}

float read_sensor() {
    int readings[10];
    float total = 0.0;

    for (int i = 0; i < 10; i++) {
        usleep(250000); // Wait 250ms between readings
        total += (float)gpioRead(SENSOR_PIN);
    }

    total /= 10;
    return total;
}

