    if (init_pigpio() != 0) {
        return 1;
    }

    while (1) {
        float co2_level = read_sensor();
        log_message(fmt::format("CO2 level: {:.2f} ppm", co2_level).c_str());

        if (co2_level > CO2_THRESHOLD) {
            gpioWrite(RELAY_PIN, 1);
            log_message("Activating ventilation fan");
        } else {
            gpioWrite(RELAY_PIN, 0);
            log_message("Ventilation fan deactivated");
        }

        sleep(60); // Check sensor every minute
    }

    gpioTerminate();
    return 0;
}
