    return gpioRead(gpio);
}

// Function to activate the buzzer
void activate_buzzer(int gpio, int duration_ms) {
    gpioWrite(gpio, 1); // Turn buzzer on
    gpioDelay(duration_ms * 1000); // Delay in microseconds
    gpioWrite(gpio, 0); // Turn buzzer off
}

// Signal handler for graceful shutdown
