    // Initialize syslog
    openlog("motion_detector", LOG_PID | LOG_CONS, LOG_USER);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        log_message(LOG_ERR, "pigpio initialisation failed");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(PIR_GPIO, PI_INPUT);
    gpioSetMode(BUZZER_GPIO, PI_OUTPUT);

    // Set pull-down resistor for PIR sensor (optional, adjust as needed)
    gpioSetPullUpDown(PIR_GPIO, PI_PUD_DOWN);

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    log_message(LOG_INFO, "Motion detector started");

    // Main loop
    while (!terminate) {
        int pir_value = read_pir_sensor(PIR_GPIO);

        if (pir_value == 1) {
            char *timestamp = get_timestamp();
            char message[100];
