#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <time.h>
#include <pigpio.h>

// Define GPIO pins
#define PIR_PIN 4
#define BUZZER_PIN 18
#define STOP_BUTTON_PIN 17

// Global variables
static volatile int running = 1;
static volatile int buzzer_state = 0; // 0: off, 1: on
static volatile unsigned long last_interrupt_time = 0;

// Function prototypes
void motion_detected(int gpio, int level, unsigned int tick, void *user);
void stop_button_pressed(int gpio, int level, unsigned int tick, void *user);
void cleanup(int signum);

// Motion detection interrupt handler
void motion_detected(int gpio, int level, unsigned int tick, void *user) {
    unsigned long now = gpioTick();
    if (now - last_interrupt_time > 200000) { // 200ms debounce
        last_interrupt_time = now;
        if (level == 1) { // Rising edge (motion detected)
            printf("Motion detected!\n");
            if (!buzzer_state) {
                gpioWrite(BUZZER_PIN, 1); // Turn buzzer on
                buzzer_state = 1;
            }
        }
    }
}

// Stop button interrupt handler
void stop_button_pressed(int gpio, int level, unsigned int tick, void *user) {
    if (level == 0) { // Falling edge (button pressed)
        printf("Stop button pressed. Stopping buzzer.\n");
        gpioWrite(BUZZER_PIN, 0); // Turn buzzer off
        buzzer_state = 0;
    }
}

// Signal handler for graceful shutdown
void cleanup(int signum) {
    printf("Cleaning up and exiting...\n");
    running = 0;
    gpioTerminate(); // Terminate pigpio
    exit(0);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(PIR_PIN, PI_INPUT);
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    gpioSetMode(STOP_BUTTON_PIN, PI_INPUT);
    gpioSetPullUpDown(STOP_BUTTON_PIN, PI_PUD_UP); // Enable pull-up resistor

    // Set up interrupt handlers
    if (gpioSetISRFuncEx(PIR_PIN, RISING_EDGE, 0, motion_detected, NULL) != 0) {
        fprintf(stderr, "Failed to set ISR for PIR pin\n");
        gpioTerminate();
        return 1;
    }

    if (gpioSetISRFuncEx(STOP_BUTTON_PIN, FALLING_EDGE, 0, stop_button_pressed, NULL) != 0) {
        fprintf(stderr, "Failed to set ISR for stop button\n");
        gpioTerminate();
        return 1;
    }

    // Set up signal handlers
    signal(SIGINT, cleanup); // Ctrl+C
    signal(SIGTERM, cleanup); // Termination signal

    printf("Motion detection system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (running) {
        gpioDelay(100); // Reduce CPU usage
    }

    return 0;
}

