#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>

#define PIR_GPIO 17
#define LOG_FILE "security_log.txt"

volatile sig_atomic_t program_running = 1;

// Function to handle signals (e.g., Ctrl+C)
void signal_handler(int signal) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully.\n", signal);
}

// Function to get the current timestamp as a string
char* get_timestamp() {
    time_t now = time(NULL);
    struct tm *tstruct;
    char *buf = malloc(20 * sizeof(char)); // Allocate memory for the timestamp string
    if (buf == NULL) {
        perror("Failed to allocate memory for timestamp");
        return NULL;
    }
    tstruct = localtime(&now);
    strftime(buf, 20, "%Y-%m-%d %H:%M:%S", tstruct);
    return buf;
}

// Function to log a message to the log file
int log_event(const char *message) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("Failed to open log file");
        return 1; // Indicate failure
    }

    char *timestamp = get_timestamp();
    if (timestamp == NULL) {
        fclose(fp);
        return 1;
    }

    fprintf(fp, "%s: %s\n", timestamp, message);
    free(timestamp); // Free the allocated memory

    if (ferror(fp)) {
        perror("Error writing to log file");
        fclose(fp);
        return 1;
    }

    if (fclose(fp) != 0) {
        perror("Error closing log file");
        return 1;
    }
    return 0; // Indicate success
}

// Function to read the PIR sensor value with safety checks
int read_pir_sensor() {
    int pir_value = gpioRead(PIR_GPIO);
    if (pir_value != 0 && pir_value != 1) {
        fprintf(stderr, "Error: Invalid PIR sensor reading: %d\n", pir_value);
        return -1; // Indicate error
    }
    return pir_value;
}

int main() {
    // Install signal handler
    signal(SIGINT, signal_handler);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO mode for PIR sensor
    gpioSetMode(PIR_GPIO, PI_INPUT);

    // Simple debouncing implementation
    time_t last_activation_time = 0;

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    while (program_running) {
        int pir_value = read_pir_sensor();
        if (pir_value == -1) {
            // Handle sensor reading error (e.g., log it)
            fprintf(stderr, "Error reading PIR sensor, continuing...\n");
        } else if (pir_value == 1) {
            time_t current_time = time(NULL);
            // Debouncing: Check if enough time has passed since the last activation
            if (difftime(current_time, last_activation_time) > 1.0) { // 1 second debounce
                if (log_event("Motion detected!") != 0) {
                    fprintf(stderr, "Error logging motion event.\n");
                }
                last_activation_time = current_time;
                printf("Motion detected!\n");
            }
        }

        gpioDelay(100); // Check every 100ms
    }

    // Cleanup
    gpioTerminate();
    printf("Program terminated.\n");
    return 0;
}

