1. Install the `wiringPi` library by following the instructions here: https://projects.drogon.net/raspberry-pi/wiringpi/install-wiringpi-on-your-raspberry-pi/

2. Create a new C file called `pir_motion_detector.c` and paste the following code:

```c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/time.h>
#include <wiringPi.h>

#define PIR_SENSOR_PIN 17
#define LOG_FILE "motion_log.txt"

int main(void) {
    int pir_state = 0;
    FILE *log_file;
    struct timeval tv;

    if (wiringPiSetup() == -1) {
        printf("Failed to initialize wiringPi!\n");
        return 1;
    }

    pinMode(PIR_SENSOR_PIN, INPUT);

    if ((log_file = fopen(LOG_FILE, "a")) == NULL) {
        printf("Failed to open log file: %s\n", LOG_FILE);
        return 1;
    }

    while (1) {
        if (digitalRead(PIR_SENSOR_PIN) == HIGH) {
            if (pir_state == 0) {
                gettimeofday(&tv, NULL);
                fprintf(log_file, "%lu.%06lu Motion detected at %s\n",
                        tv.tv_sec, tv.tv_usec, ctime(&tv.tv_sec));
                pir_state = 1;
            }
        } else if (pir_state == 1) {
            pir_state = 0;
        }

        usleep(500000); // Sleep for 0.5 seconds
    }

    fclose(log_file);
    return 0;
}
```

