#define PIR_GPIO 17
#define RELAY_GPIO 27
#define SERVER_IP "192.168.1.100"
#define SERVER_PORT 5000

static volatile int running = 1;

void signal_handler(int sig) {
    running = 0;
}

int init_gpio() {
    if (gpioInitialise() < 0) {
        return -1;
    }
    gpioSetMode(PIR_GPIO, PI_INPUT);
    gpioSetMode(RELAY_GPIO, PI_OUTPUT);
    return 0;
}

int read_pir_sensor() {
    return gpioRead(PIR_GPIO);
}

void control_relay(int state) {
    gpioWrite(RELAY_GPIO, state);
}

void log_event(const char *event_type) {
    FILE *fp = fopen("door_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening door_log.txt");
        return;
    }
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "[%d-%02d-%02d %02d:%02d:%02d] %s\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, event_type);
    fclose(fp);
}

int send_udp_message(const char *event_type) {
    int sockfd;
    struct sockaddr_in servaddr;
    char message[256];
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);

    sprintf(message, "%d-%02d-%02d %02d:%02d:%02d,%s", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, event_type);

    sockfd = socket(AF_INET, SOCK_DGRAM, 0);
    if (sockfd < 0) {
        perror("socket creation failed");
        return -1;
    }

    memset(&servaddr, 0, sizeof(servaddr));
    servaddr.sin_family = AF_INET;
    servaddr.sin_port = htons(SERVER_PORT);
    if (inet_pton(AF_INET, SERVER_IP, &servaddr.sin_addr) <= 0) {
        perror("inet_pton failed");
        close(sockfd);
        return -1;
    }

    if (sendto(sockfd, (const char *)message, strlen(message), 0, (const struct sockaddr *)&servaddr, sizeof(servaddr)) < 0) {
        perror("sendto failed");
        close(sockfd);
        return -1;
    }

    close(sockfd);
    return 0;
}

int main() {
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    if (init_gpio() != 0) {
        FILE *fp = fopen("door_log.txt", "a");
        if (fp != NULL) {
            fprintf(fp, "GPIO initialization failed!\n");
            fclose(fp);
        }
        return 1;
    }

    printf("Environmental Monitoring System started. Press Ctrl+C to exit.\n");

    int door_open = 0; // Initially, assume the door is closed.

    while (running) {
        int pir_value = read_pir_sensor();
        if (pir_value == 1) {
            printf("Motion detected!\n");
            if (!door_open) {
                control_relay(1); // Open the door
                log_event("Door Opened");
                send_udp_message("Door Opened");
                door_open = 1;
                gpioDelay(5000); // Keep the door open for 5 seconds
                control_relay(0); // Close the door
                log_event("Door Closed");
                send_udp_message("Door Closed");
                door_open = 0;

            }
        }
        gpioDelay(100); // Check every 100ms
    }

    gpioTerminate();
    printf("Environmental Monitoring System stopped.\n");
    return 0;
}

