// Define GPIO pins
#define SENSOR_1_PIN 17
#define SENSOR_2_PIN 18
#define BUZZER_PIN 27

// Global variables
FILE *log_file = NULL;
int running = 1;

// Structure to hold sensor data (example of using struct)
typedef struct {
    int pin;
    int sensor_number;
} sensor_t;

sensor_t sensors[] = {
    {SENSOR_1_PIN, 1},
    {SENSOR_2_PIN, 2}
};

int num_sensors = sizeof(sensors) / sizeof(sensors[0]);

// Function prototypes
int initialize_gpio();
int read_sensor(int gpio_pin);
void activate_buzzer(int duration_ms);
int log_event(int sensor_number);
void signal_handler(int signum);

// Function to initialize GPIO pins
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    for (int i = 0; i < num_sensors; i++) {
        gpioSetMode(sensors[i].pin, PI_INPUT);
        gpioSetPullUpDown(sensors[i].pin, PI_PUD_DOWN); // Or PI_PUD_UP, depending on your wiring
    }

    gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    gpioWrite(BUZZER_PIN, 0); // Ensure buzzer is off initially

    return 0;
}

// Function to read sensor value
int read_sensor(int gpio_pin) {
    return gpioRead(gpio_pin);
}

// Function to activate the buzzer
void activate_buzzer(int duration_ms) {
    gpioWrite(BUZZER_PIN, 1); // Turn buzzer on
    gpioDelay(duration_ms);
    gpioWrite(BUZZER_PIN, 0); // Turn buzzer off
}

// Function to log the event to a file
int log_event(int sensor_number) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    log_file = fopen("entry_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file\n");
        return -1;
    }

    fprintf(log_file, "%s, Sensor %d, Motion Detected\n", timestamp, sensor_number);
    fclose(log_file);

    return 0;
}

// Signal handler function
void signal_handler(int signum) {
    printf("Caught signal %d, exiting gracefully...\n", signum);
    running = 0;

    // Disable buzzer
    gpioWrite(BUZZER_PIN, 0);

    // Close log file (if open)
    if (log_file != NULL) {
        fclose(log_file);
    }

    // Terminate pigpio
    gpioTerminate();

    exit(0);
}

int main() {
    // Initialize GPIO
    if (initialize_gpio() != 0) {
        return 1;
    }

    // Set up signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Entry Access Logging System started. Press Ctrl+C to exit.\n");

    // Main loop
    while (running) {
        for (int i = 0; i < num_sensors; i++) {
            int sensor_value = read_sensor(sensors[i].pin);
            if (sensor_value == 1) {
                printf("Motion detected on Sensor %d\n", sensors[i].sensor_number);
                log_event(sensors[i].sensor_number);
                activate_buzzer(2000); // Buzzer for 2 seconds
                gpioDelay(5000); // Debounce delay: avoid multiple triggers from one motion
            }
        }
        gpioDelay(100); // Check sensors every 100ms
    }

    // Cleanup (should not reach here if signal handler works correctly)
    gpioWrite(BUZZER_PIN, 0);
    gpioTerminate();
    return 0;
}

