#define PIR_PIN 17
#define BUZZER_PIN 18

// Debounce time in milliseconds
#define DEBOUNCE_TIME 50

// Buzzer duration in milliseconds
#define BUZZER_DURATION 500

// Global flag to indicate program termination
volatile sig_atomic_t terminate = 0;

// Function prototypes
void motion_detected_callback(int gpio, int level, uint32_t tick, void *userdata);
void buzzer_on(int gpio);
void buzzer_off(int gpio);
void log_timestamp(const char *filename);
void signal_handler(int signal);

// Signal handler function
void signal_handler(int signal) {
    terminate = 1;
    printf("\nCaught signal %d, terminating gracefully...\n", signal);
}

// Motion detection callback function
void motion_detected_callback(int gpio, int level, uint32_t tick, void *userdata) {
    if (level == 1) { // Rising edge - motion detected
        printf("Motion detected!\n");
        log_timestamp("motion.log");
        buzzer_on(BUZZER_PIN);
        gpioDelay(BUZZER_DURATION * 1000); // Delay for buzzer duration
        buzzer_off(BUZZER_PIN);
    }
}

// Function to turn the buzzer on
void buzzer_on(int gpio) {
    if (gpioWrite(gpio, 1) != 0) {
        fprintf(stderr, "Error writing to GPIO %d\n", gpio);
    }
}

// Function to turn the buzzer off
void buzzer_off(int gpio) {
    if (gpioWrite(gpio, 0) != 0) {
        fprintf(stderr, "Error writing to GPIO %d\n", gpio);
    }
}

// Function to log timestamp to file
void log_timestamp(const char *filename) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[30];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%dT%H:%M:%S%z", timeinfo);

    FILE *fp = fopen(filename, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening file %s\n", filename);
        return;
    }

    fprintf(fp, "%s\n", timestamp);
    fclose(fp);
}

